1092 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1093 |     function applyLocalPatch(content, ops) {
1094 |         let lines = content.split('\n');
1095 |         let logs = [];
1096 |         let success = true;
1097 | 
1098 |         if (typeof ops === 'string') {
1099 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1100 |         }
1101 | 
1102 |         ops.forEach(op => {
1103 |             if (op.action === 'comment') return;
1104 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1105 |             
1106 |             if (op.action === 'replace_block') {
1107 |                 // Strategy 1: Exact String Match (Fastest)
1108 |                 const currentStr = lines.join('\n');
1109 |                 if (currentStr.includes(op.find_block)) {
1110 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1111 |                     logs.push('Exact match applied');
1112 |                     return;
1113 |                 }
1114 | 
1115 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1116 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1117 |                 if (searchLines.length === 0) return;
1118 | 
1119 |                 let matchStart = -1;
1120 |                 let matchEnd = -1;
1121 | 
1122 |                 // Scan file lines
1123 |                 for (let i = 0; i < lines.length; i++) {
1124 |                     // If first line matches (ignoring whitespace)
1125 |                     if (lines[i].trim() === searchLines[0]) {
1126 |                         // Check subsequent lines
1127 |                         let allMatch = true;
1128 |                         let fileOffset = 0;
1129 |                         let searchOffset = 1;
1130 |                         
1131 |                         while (searchOffset < searchLines.length) {
1132 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1133 |                             const nextFile = lines[i + fileOffset + 1].trim();
1134 |                             // Skip empty lines in file if they aren't in search block
1135 |                             if (nextFile === '') {
1136 |                                 fileOffset++;
1137 |                                 continue;
1138 |                             }
1139 |                             if (nextFile !== searchLines[searchOffset]) {
1140 |                                 allMatch = false;
1141 |                                 break;
1142 |                             }
1143 |                             fileOffset++;
1144 |                             searchOffset++;
1145 |                         }
1146 | 
1147 |                         if (allMatch) {
1148 |                             matchStart = i;
1149 |                             matchEnd = i + fileOffset;
1150 |                             break;
1151 |                         }
1152 |                     }
1153 |                 }
1154 | 
1155 |                 if (matchStart !== -1) {
1156 |                     // Replace the range of lines
1157 |                     const replacement = op.replace_with.split('\n');
1158 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1159 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1160 |                 } else {
1161 |                     success = false;
1162 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1163 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1164 |                 }
1165 |             }
1166 |         });
1167 |         return { content: lines.join('\n'), success, logs };
1168 |     }
