// 2. Self-Healing (Healer)
async function consultAI(fileContent: string, failedOp: any, failReason: string, config?: AIConfig): Promise<{ fixedOp: any | null; reason: string; score: number }> {
  console.log(`--- CONSULT AI (HEALER) START for ${failedOp?.action} ---`);

  const systemInstruction = `You are the Conduit Self-Healing Patch Engine.
  A patch operation failed because of a mismatch. Your goal is to HEAL it by finding the correct location.

  PRIORITY: AGGRESSIVE FUZZY MATCHING.
  The user is likely correct that the code exists, but provided a slightly outdated or malformatted block.

  SEARCH STRATEGY:
  1. Ignore whitespace/indentation differences completely.
  2. Look for semantic equivalents (e.g. "const x = 1" vs "const x=1").
  3. Look for the code surrounding the target (context matching).
  4. If variables are renamed but structure is identical, MATCH IT.

  REPORTING:
  - You MUST populate the "explanation" field with your reasoning. Tell me exactly what differed (e.g., "Found match on line 50, but indentation was different").
  - If you cannot find it, explain WHY (e.g., "Function 'init' is missing entirely").

  Use the 'suggest_fix' tool to return your findings.`;

  const tools = [{ 
    type: "function",
    function: { 
        name: "suggest_fix", 
        description: "Return corrected patch params", 
        parameters: { 
            type: "object", 
            properties: { 
                can_fix: { type: "boolean" }, 
                confidence_score: { 
                    type: "number",
                    description: "Confidence score from 0 to 100 (e.g. 95, not 0.95)"
                }, 
                explanation: { type: "string" }, 
                start_line: { type: ["integer", "null"] }, 
                end_line: { type: ["integer", "null"] }, 
                anchor_line: { type: ["integer", "null"] }, 
                new_anchor_text: { type: ["string", "null"] } 
            }, 
            required: ["can_fix", "explanation", "confidence_score"] 
        } 
    } 
  }];

  try {
    const userPrompt = "File:\n" + getNumberedContent(fileContent) + "\nOp:\n" + JSON.stringify(failedOp) + "\nError:\n" + failReason;
    console.log("[Healer] Prompt Sent (Excluding File):", systemInstruction + "\nOp: " + JSON.stringify(failedOp) + "\nReason: " + failReason);

    const messages = [
        { role: "system", content: systemInstruction },
        { role: "user", content: userPrompt }
    ];

    const result = await genericRequestAI('fast_fix', messages, config, tools);
    console.log("🔥 [HEALER RAW DEBUG]:", JSON.stringify(result, null, 2));

    const toolCall = result.tool_calls?.[0];
    if (!toolCall || toolCall.function.name !== "suggest_fix") {
        // Fallback: If AI refused to call tool, return its text response as the reason
        const rawText = result.content || "AI returned no content and no tool calls.";
        return { fixedOp: null, reason: `AI Refusal: ${rawText.substring(0, 200)}`, score: 0 };
    }

    const args = JSON.parse(toolCall.function.arguments);
    if (!args || !args.can_fix || args.confidence_score < 60) return { fixedOp: null, reason: args?.explanation || "No match", score: args?.confidence_score || 0 };

    const newOp = { ...failedOp, is_ai_fix: true };
    if (args.start_line && args.end_line) { newOp.ai_strategy = "range_replace"; newOp.start_line = args.start_line; newOp.end_line = args.end_line; } 
    else if (args.anchor_line) { newOp.ai_strategy = "line_insert"; newOp.anchor_line = args.anchor_line; }
    else if (args.new_anchor_text) { newOp.anchor = args.new_anchor_text; }
    return { fixedOp: newOp, reason: args.explanation, score: args.confidence_score };
  } catch (e: any) { console.error("[Healer] Error:", e); return { fixedOp: null, reason: e.message, score: 0 }; }
}

