 965 |     function resolvePath(base, relative) {
 966 |         const stack = base.split('/');
 967 |         stack.pop(); 
 968 |         const parts = relative.split('/');
 969 |         for (let i = 0; i < parts.length; i++) {
 970 |             if (parts[i] === '.') continue;
 971 |             if (parts[i] === '..') stack.pop();
 972 |             else stack.push(parts[i]);
 973 |         }
 974 |         return stack.join('/');
 975 |     }
