2675 | async function downloadArtifact(runId) {
2676 |         const toast = document.createElement('div');
2677 |         toast.innerHTML = `<span style="animation:pulse 1s infinite">🔍 Searching for artifact link...</span>`;
2678 |         toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:10px 20px; border-radius:30px; z-index:9999; font-size:12px;";
2679 |         document.body.appendChild(toast);
2680 | 
2681 |         try {
2682 |             // 1. Get the jobs for this run to find the build job
2683 |             const resJobs = await fetch(CONFIG.funcUrl, { 
2684 |                 method: 'POST', 
2685 |                 headers: {'Content-Type': 'application/json'}, 
2686 |                 body: apiBody({ action: 'fetch_workflow_jobs', run_id: runId }) 
2687 |             });
2688 |             const dataJobs = await resJobs.json();
2689 |             
2690 |             // Look for a job that likely uploaded artifacts (usually named 'build' or is the successful one)
2691 |             const buildJob = dataJobs.jobs.find(j => j.name.toLowerCase().includes('build') || j.conclusion === 'success');
2692 |             
2693 |             if (!buildJob) {
2694 |                 toast.remove();
2695 |                 return alert("Could not identify the build job for this run.");
2696 |             }
2697 | 
2698 |             // 2. Fetch the logs for that specific job
2699 |             const resLogs = await fetch(CONFIG.funcUrl, { 
2700 |                 method: 'POST', 
2701 |                 headers: {'Content-Type': 'application/json'}, 
2702 |                 body: apiBody({ action: 'fetch_job_logs', job_id: buildJob.id }) 
2703 |             });
2704 |             const dataLogs = await resLogs.json();
2705 |             const logs = dataLogs.logs || "";
2706 | 
2707 |             // 3. Extract the URL using Regex (looking for the specific pattern in your logs)
2708 |             // Pattern: Artifact download URL: https://github.com/...
2709 |             const urlMatch = logs.match(/Artifact download URL:\s*(https?:\/\/[^\s]+)/);
2710 | 
2711 |             if (urlMatch && urlMatch[1]) {
2712 |                 toast.style.background = "var(--prod)";
2713 |                 toast.innerText = "📥 Starting Download...";
2714 |                 
2715 |                 // Trigger the download in a new tab
