2717 |                 
2718 |                 setTimeout(() => toast.remove(), 2000);
2719 |             } else {
2720 |                 toast.remove();
2721 |                 alert("Artifact URL not found in logs. It may still be processing or expired.");
2722 |             }
2723 | 
2724 |         } catch (e) {
2725 |             toast.remove();
2726 |             console.error("Download Error:", e);
2727 |             alert("Failed to extract artifact URL: " + e.message);
2728 |         }
