1179 |             if (index >= currentErrors.length) return true; // All initial errors processed
1180 | 
1181 |             const err = currentErrors[index];
1182 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
1183 |             status.style.color = "#eab308"; // Dev yellow
1184 | 
1185 |             try {
1186 |                 // 1. Get Patch from AI
1187 |                 const res = await fetch(CONFIG.funcUrl, { 
1188 |                     method: 'POST', 
1189 |                     headers: {'Content-Type': 'application/json'},
1190 |                     body: apiBody({ 
1191 |                         action: 'propose_syntax_fix', 
1192 |                         code: currentCode, 
1193 |                         error: err 
1194 |                     })
1195 |                 });
1196 |                 const data = await res.json();
1197 |                 const ops = data.operations;
1198 | 
1199 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
1200 | 
1201 |                 // 2. Apply Patch Locally
1202 |                 const patchResult = applyLocalPatch(currentCode, ops);
1203 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
1204 | 
1205 |                 currentCode = patchResult.content;
1206 |                 document.getElementById('ef-code').value = currentCode; // Update UI
1207 | 
1208 |                 // 3. Re-Validate
1209 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
1210 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
1211 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
1212 |                 });
1213 |                 const scanData = await scanRes.json();
1214 | 
1215 |                 if (scanData.valid) {
1216 |                     status.innerText = "✅ Syntax Fixed!";
1217 |                     return true;
1218 |                 } else {
1219 |                     // If errors remain, update list and Prompt user
