private fun startMonitoring() {
    scope.launch {
        while (isActive) {
            val inSettings = currentPackage.contains("settings") || currentPackage.contains("accessibility")

            // 1. SELF-HEALING: Check if Overlay Permission was revoked
            // Only nag if NOT already in settings
