private suspend fun checkRules() {
    // -1. MANUAL LOCKOUT CHECK (Highest Priority)
    val remainingLockout = TimeManager.getLockoutRemaining(this)
    if (remainingLockout > 0) {
         triggerBreak("MANUAL_LOCKOUT", remainingLockout)
         return
    }

    // -0.5 SNOOZE CHECK (Priority)
    // If user snoozed, we skip the break logic completely for 5 mins
    if (System.currentTimeMillis() < TimeManager.snoozeUntil) {
         hideBanner() // Clear any warnings if they exist
         return
    }

    // SAFETY CHECK: Is the user doing something critical? (Whitelist)
    if (isCriticalAppForeground()) {
         if (isBreakDue()) {
             showBanner("Break Delayed: Safety Mode Active")
         }
         return
    }

