private fun isCriticalAppForeground(): Boolean {
    // SAFETY WHITELIST: Apps that should pause the timer/break
    val safeApps = setOf(
        // Navigation
        "com.google.android.apps.maps", "com.waze", "com.yandex.yandexmaps",
        // Communication
        "com.google.android.dialer", "com.samsung.android.dialer", "com.android.server.telecom", 
        "us.zoom.videomeetings", "com.microsoft.teams", "com.skype.raider",
        // Rideshare
        "com.ubercab", "me.lyft.android",
        // Camera (Annoying if interrupted)
        "com.android.camera", "com.sec.android.app.camera", "com.google.android.GoogleCamera"
    )
    return safeApps.contains(currentPackage) || 
           currentPackage.contains("maps") || 
           currentPackage.contains("dialer") ||
           currentPackage.contains("call") ||
           currentPackage.contains("camera")
}

