@Composable
fun SetupCard() {
    val context = LocalContext.current

    // Status Checks
    val isAdmin = remember { mutableStateOf(false) }
    val isOverlay = remember { mutableStateOf(false) }
    val isBattery = remember { mutableStateOf(false) }

    // Refresh statuses whenever the user returns to the app
    LaunchedEffect(Unit) {
        while(true) {
            val dpm = context.getSystemService(Context.DEVICE_POLICY_SERVICE) as android.app.admin.DevicePolicyManager
            isAdmin.value = dpm.isAdminActive(ComponentName(context, AdminReceiver::class.java))
            isOverlay.value = Settings.canDrawOverlays(context)
            val pm = context.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager
            isBattery.value = pm.isIgnoringBatteryOptimizations(context.packageName)
            kotlinx.coroutines.delay(1000)
        }
    }

    Card(
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
        modifier = Modifier.fillMaxWidth()
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text("SYSTEM INTEGRITY", style = MaterialTheme.typography.labelLarge, color = Color.Gray)
            Spacer(modifier = Modifier.height(12.dp))

            SetupItem("Device Admin", Icons.Filled.AdminPanelSettings, isAdmin.value) {
                if (!isAdmin.value) {
                    val comp = ComponentName(context, AdminReceiver::class.java)
                    val i = Intent(android.app.admin.DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN)
                    i.putExtra(android.app.admin.DevicePolicyManager.EXTRA_DEVICE_ADMIN, comp)
                    startActivity(i)
                }
            }
            SetupItem("Accessibility Monitor", Icons.Filled.Visibility, false) { // Accessibility check is complex, keep as interactive
                startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS))
            }
            SetupItem("Overlay Permission", Icons.Filled.Layers, isOverlay.value) {
                if (!isOverlay.value) {
                    val i = Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION, Uri.parse("package:$packageName"))
                    startActivity(i)
                }
            }
            SetupItem("Battery Immunity", Icons.Filled.BatteryAlert, isBattery.value) {
                if (!isBattery.value) {
                    try {
                        val i = Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS, Uri.parse("package:$packageName"))
                        startActivity(i)
                    } catch (e: Exception) {
                        startActivity(Intent(Settings.ACTION_IGNORE_BATTERY_OPTIMIZATION_SETTINGS))
                    }
                }
            }
        }
    }
}

