@Composable
fun SetupCard() {
    // Refresh states whenever activity is seen
    var isAdmin by remember { mutableStateOf(false) }
    var isAccess by remember { mutableStateOf(false) }
    var isOverlay by remember { mutableStateOf(false) }
    var isBattery by remember { mutableStateOf(false) }

    LaunchedEffect(Unit) {
        while(true) {
            val dpm = getSystemService(DevicePolicyManager::class.java)
            isAdmin = dpm.isAdminActive(ComponentName(this@MainActivity, AdminReceiver::class.java))

            val enabled = Settings.Secure.getString(contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES) ?: ""
            isAccess = enabled.contains(packageName)

            isOverlay = Settings.canDrawOverlays(this@MainActivity)

            val pm = getSystemService(android.os.PowerManager::class.java)
            isBattery = pm.isIgnoringBatteryOptimizations(packageName)

            delay(1000)
        }
    }

    Card(
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
        modifier = Modifier.fillMaxWidth()
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text("SYSTEM INTEGRITY", style = MaterialTheme.typography.labelLarge, color = Color.Gray)
            Spacer(modifier = Modifier.height(12.dp))

            SetupItem("Device Admin", Icons.Filled.AdminPanelSettings, isAdmin) {
                val comp = ComponentName(this@MainActivity, AdminReceiver::class.java)
                val i = Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN)
                i.putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN, comp)
                startActivity(i)
            }
            SetupItem("Accessibility Monitor", Icons.Filled.Visibility, isAccess) {
                startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS))
            }
            SetupItem("Overlay Permission", Icons.Filled.Layers, isOverlay) {
                val i = Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION, Uri.parse("package:$packageName"))
                startActivity(i)
            }
            SetupItem("Battery Immunity", Icons.Filled.BatteryAlert, isBattery) {
                try {
                    val i = Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS, Uri.parse("package:$packageName"))
                    startActivity(i)
                } catch (e: Exception) {
                    startActivity(Intent(Settings.ACTION_IGNORE_BATTERY_OPTIMIZATION_SETTINGS))
                }
            }
        }
    }
}

