private fun startMonitoring() {
    scope.launch {
        while (isActive) {
            // 0. STOP ALL NAGGING IF PROTECTION IS DISABLED (Nuke Mode)
            if (NukeManager.isProtectionDisabled(applicationContext)) {
                delay(10000)
                continue
            }

            val lowPkg = currentPackage.lowercase()
            val inSettings = lowPkg.contains("settings") || 
                           lowPkg.contains("accessibility") || 
                           lowPkg.contains("packageinstaller") ||
                           lowPkg.contains("systemui")

            // 1. SELF-HEALING: Overlay Permission
            if (!android.provider.Settings.canDrawOverlays(applicationContext)) {
                if (!inSettings) {
                    val i = Intent(android.provider.Settings.ACTION_MANAGE_OVERLAY_PERMISSION, android.net.Uri.parse("package:$packageName"))
                    i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                    startActivity(i)
                }
            }
            // 2. ENFORCE AUTO TIME
            else if ((android.provider.Settings.Global.getInt(contentResolver, android.provider.Settings.Global.AUTO_TIME, 0) != 1 ||
                      android.provider.Settings.Global.getInt(contentResolver, android.provider.Settings.Global.AUTO_TIME_ZONE, 0) != 1)) {
                if (!inSettings) {
                    val i = Intent(android.provider.Settings.ACTION_DATE_SETTINGS)
                    i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                    startActivity(i)
                }
            }
            // 3. ENFORCE ENGLISH LANGUAGE
            else if (java.util.Locale.getDefault().language != "en") {
                if (!inSettings) {
                    val i = Intent(android.provider.Settings.ACTION_LOCALE_SETTINGS)
                    i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                    startActivity(i)
                }
            }

