@Composable
fun SetupCard() {
    val context = android.compose.ui.platform.LocalContext.current
    var isAdmin by remember { mutableStateOf(false) }
    var isAccess by remember { mutableStateOf(false) }
    var isOverlay by remember { mutableStateOf(false) }
    var isBattery by remember { mutableStateOf(false) }

    // Update states every second
    LaunchedEffect(Unit) {
        while(true) {
            val dpm = context.getSystemService(Context.DEVICE_POLICY_SERVICE) as DevicePolicyManager
            isAdmin = dpm.isAdminActive(ComponentName(context, AdminReceiver::class.java))

            val enabledServices = Settings.Secure.getString(context.contentResolver, Settings.Secure.ENABLED_ACCESSIBILITY_SERVICES) ?: ""
            isAccess = enabledServices.contains(context.packageName)

            isOverlay = Settings.canDrawOverlays(context)

            val pm = context.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager
            isBattery = pm.isIgnoringBatteryOptimizations(context.packageName)

            delay(1000)
        }
    }

    Card(
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
        modifier = Modifier.fillMaxWidth()
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text("SYSTEM INTEGRITY", style = MaterialTheme.typography.labelLarge, color = Color.Gray)
            Spacer(modifier = Modifier.height(12.dp))

            SetupItem("Device Admin", Icons.Filled.AdminPanelSettings, isAdmin) {
                if (isAdmin) {
                    android.widget.Toast.makeText(context, "Admin Active", android.widget.Toast.LENGTH_SHORT).show()
                } else {
                    val comp = ComponentName(context, AdminReceiver::class.java)
                    val i = Intent(DevicePolicyManager.ACTION_ADD_DEVICE_ADMIN)
                    i.putExtra(DevicePolicyManager.EXTRA_DEVICE_ADMIN, comp)
                    startActivity(i)
                }
            }
            SetupItem("Accessibility Monitor", Icons.Filled.Visibility, isAccess) {
                if (isAccess) {
                    android.widget.Toast.makeText(context, "Service Active", android.widget.Toast.LENGTH_SHORT).show()
                } else {
                    startActivity(Intent(Settings.ACTION_ACCESSIBILITY_SETTINGS))
                }
            }
            SetupItem("Overlay Permission", Icons.Filled.Layers, isOverlay) {
                if (isOverlay) {
                    android.widget.Toast.makeText(context, "Overlay Active", android.widget.Toast.LENGTH_SHORT).show()
                } else {
                    val i = Intent(Settings.ACTION_MANAGE_OVERLAY_PERMISSION, Uri.parse("package:$packageName"))
                    startActivity(i)
                }
            }
            SetupItem("Battery Immunity", Icons.Filled.BatteryAlert, isBattery) {
                if (isBattery) {
                    android.widget.Toast.makeText(context, "Battery Exempt", android.widget.Toast.LENGTH_SHORT).show()
                } else {
                    try {
                        val i = Intent(Settings.ACTION_REQUEST_IGNORE_BATTERY_OPTIMIZATIONS, Uri.parse("package:$packageName"))
                        startActivity(i)
                    } catch (e: Exception) {
                        startActivity(Intent(Settings.ACTION_IGNORE_BATTERY_OPTIMIZATION_SETTINGS))
                    }
                }
            }
        }
    }
}

