private fun checkSystemIntegrity() {
    // 1. Check Overlay Permission
    if (!android.provider.Settings.canDrawOverlays(this)) {
        val i = Intent(android.provider.Settings.ACTION_MANAGE_OVERLAY_PERMISSION)
        i.data = android.net.Uri.parse("package:$packageName")
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        startActivity(i)
        return
    }

    // 2. Enforce Auto Time (Essential for tracking accuracy)
    val isAutoTime = android.provider.Settings.Global.getInt(contentResolver, android.provider.Settings.Global.AUTO_TIME, 0) == 1
    val isAutoZone = android.provider.Settings.Global.getInt(contentResolver, android.provider.Settings.Global.AUTO_TIME_ZONE, 0) == 1

    if (!isAutoTime || !isAutoZone) {
        val i = Intent(android.provider.Settings.ACTION_DATE_SETTINGS)
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        startActivity(i)
        return
    }

    // 3. Enforce English (Essential for text-based security scanning)
    if (java.util.Locale.getDefault().language != "en") {
        val i = Intent(android.provider.Settings.ACTION_LOCALE_SETTINGS)
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        startActivity(i)
    }
}

