override fun onAccessibilityEvent(event: AccessibilityEvent?) {
    if (event == null) return

    val pkg = event.packageName?.toString() ?: ""

    // 0. SELF-EXCLUSION: Do not monitor our own app
    if (pkg == packageName) return

    // 0.5 NUKE CHECK: If Nuke Protocol is active, we STOP here.
    if (NukeManager.isProtectionDisabled(applicationContext)) {
        return
    }

    // FIX: Session Leaking. Reset verification when window state changes
    if (event.eventType == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
        verifiedSafeAppInfoSession = false
        currentPackage = pkg
    }

    // GLOBAL RESET: If we switch to a different app (ignore SystemUI overlays)
    if (!pkg.contains("settings") && !pkg.contains("packageinstaller") && 
        !pkg.contains("accessibility") && !pkg.contains("systemui")) {
        if (verifiedSafeAppInfoSession) {
            DebugLogger.log("Reset", "Left Settings (Pkg: $pkg). Session Invalidated.")
            verifiedSafeAppInfoSession = false
        }
    }

    // 0. DIALOG TRAP (The Backup Plan)
    // If a system dialog pops up asking to "Stop" or "Deactivate", kill it.
    if (event.className?.toString()?.contains("Dialog") == true || 
        event.className?.toString()?.contains("AlertDialog") == true) {
        val source = event.source
        if (source != null) {
            // Check if this dialog is about US
            val dialogText = StringBuilder()
            recursiveScan(source, dialogText)
            val text = dialogText.toString()

            if (text.contains("Eyecare", ignoreCase = true) && 
               (text.contains("Stop", ignoreCase = true) || text.contains("Deactivate", ignoreCase = true))) {
                performGlobalAction(GLOBAL_ACTION_BACK)
                // Also try to find the "Cancel" button and click it
                val cancelNodes = source.findAccessibilityNodeInfosByText("Cancel")
                cancelNodes.firstOrNull()?.performAction(AccessibilityNodeInfo.ACTION_CLICK)
                return
            }
        }
    }

    // 1. SETTINGS GUARD (Locked OR Unlocked)
    if (pkg.contains("settings") || pkg.contains("accessibility") || pkg.contains("packageinstaller")) {

        val allWindows = this.windows
        if (allWindows.isEmpty()) return

        for (window in allWindows) {
            val root = window.root ?: continue
            val winPkg = root.packageName?.toString() ?: ""

            // We only care about windows belonging to Settings/System
            if (!winPkg.contains("settings") && !winPkg.contains("packageinstaller") && !winPkg.contains("accessibility")) continue

            val hasEyecare = root.findAccessibilityNodeInfosByText("Eyecare").isNotEmpty() || 
                            root.findAccessibilityNodeInfosByText("EyeCare").isNotEmpty()

            if (!hasEyecare) continue

            // THREAT A: Accessibility Toggle Screen
            val trap1 = root.findAccessibilityNodeInfosByText("monitor usage").isNotEmpty()
            val trap2 = root.findAccessibilityNodeInfosByText("prevent uninstallation").isNotEmpty()

            // THREAT B: Device Admin / Deactivation Screen
            val trap3 = root.findAccessibilityNodeInfosByText("Deactivate").isNotEmpty()

            // THREAT C: App Info Page
            val hasUninstall = root.findAccessibilityNodeInfosByText("Uninstall").isNotEmpty()
            val hasForceStop = root.findAccessibilityNodeInfosByText("Force stop").isNotEmpty()
            val hasStorage = root.findAccessibilityNodeInfosByText("Storage").isNotEmpty()

            if (trap1 || trap2 || trap3 || (hasUninstall && hasForceStop) || hasStorage) {
                DebugLogger.log("SECURITY", "Threat detected in window: $winPkg. Triggering Lockdown.")
                performGlobalAction(GLOBAL_ACTION_BACK)
                startTripwire()
                return
            }
        }
    }
}

