            val trap1 = root.findAccessibilityNodeInfosByText("monitor usage").isNotEmpty()
            val trap2 = root.findAccessibilityNodeInfosByText("prevent uninstallation").isNotEmpty()

            // THREAT B: Device Admin / Deactivation Screen
            val trap3 = root.findAccessibilityNodeInfosByText("Deactivate").isNotEmpty()

            // THREAT C: App Info Page
            val hasUninstall = root.findAccessibilityNodeInfosByText("Uninstall").isNotEmpty()
            val hasForceStop = root.findAccessibilityNodeInfosByText("Force stop").isNotEmpty()
            val hasStorage = root.findAccessibilityNodeInfosByText("Storage").isNotEmpty()

            if (trap1 || trap2 || trap3 || (hasUninstall && hasForceStop) || hasStorage) {
