fun isProtectionDisabled(ctx: Context): Boolean {
    val prefs = ctx.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
    val isDisabled = prefs.getBoolean(KEY_DISABLED, false)
    if (!isDisabled) return false

    // Check for Auto-Revert
    val ts = prefs.getLong(KEY_DISABLED_TS, 0L)
    if (System.currentTimeMillis() - ts > AUTO_REVERT_MS) {
        prefs.edit().putBoolean(KEY_DISABLED, false).apply()
        return false
    }
    return true
}

