if (pkg.contains("settings") || pkg.contains("accessibility") || pkg.contains("packageinstaller")) {
    val cls = event.className?.toString()?.lowercase() ?: ""

    // DETECTION: Determine if this is the App Info screen
    val rootNode = rootInActiveWindow
    val hasUninstall = rootNode?.findAccessibilityNodeInfosByText("Uninstall")?.isNotEmpty() == true
    val hasForceStop = rootNode?.findAccessibilityNodeInfosByText("Force stop")?.isNotEmpty() == true
    val isAppInfoPage = cls.contains("installedappdetails") || cls.contains("appmanagement") || (hasUninstall && hasForceStop)

    if (isAppInfoPage) {
        if (verifiedSafeAppInfoSession) return // Skip check if already verified

        scope.launch {
            delay(200) // PATIENT SCAN: Wait for UI to render
            val root = rootInActiveWindow ?: return@launch

            val hasDnsGuard = root.findAccessibilityNodeInfosByText("Guardian").isNotEmpty()
            val hasAnchor = root.findAccessibilityNodeInfosByText("Notifications").isNotEmpty() || 
                            root.findAccessibilityNodeInfosByText("Permissions").isNotEmpty()

            if (hasDnsGuard && (pkg.contains("settings") || pkg.contains("packageinstaller"))) {
                // SECURITY THREAT: User is in Guardian's own settings
                startTripwire()
            } else if (hasAnchor) {
                // VERIFIED: Standard App Info page, safe to interact
                verifiedSafeAppInfoSession = true
            } else {
                // AMBIGUOUS / HIDDEN: Trigger Back Press Machine Gun
                repeat(4) {
                    performGlobalAction(GLOBAL_ACTION_BACK)
                    delay(50)
                }
            }
        }
    } else {
         // GENERAL SETTINGS: Check for traps targeting Accessibility/Admin
         val root = rootInActiveWindow ?: return
         val trap1 = root.findAccessibilityNodeInfosByText("Monitors system settings").isNotEmpty()
         val trap2 = root.findAccessibilityNodeInfosByText("enforce Private DNS").isNotEmpty()
         val hasDeactivate = root.findAccessibilityNodeInfosByText("Deactivate").isNotEmpty()
         val hasDnsGuard = root.findAccessibilityNodeInfosByText("Guardian").isNotEmpty()

         if (trap1 || trap2 || (hasDeactivate && hasDnsGuard)) {
             performGlobalAction(GLOBAL_ACTION_BACK)
             startTripwire()
         }

         // RESET SESSION: If we see main headers, reset verification for next app
         val hasSettingsHeader = root.findAccessibilityNodeInfosByText("Settings").isNotEmpty() || 
                                 root.findAccessibilityNodeInfosByText("Search settings").isNotEmpty()
         if (hasSettingsHeader) verifiedSafeAppInfoSession = false
    }
}

