package com.universal.app

import android.Manifest
import android.content.pm.PackageManager
import android.os.Bundle
import android.widget.Toast
import androidx.activity.ComponentActivity
import androidx.activity.compose.rememberLauncherForActivityResult
import androidx.activity.compose.setContent
import androidx.activity.result.contract.ActivityResultContracts
import androidx.camera.core.*
import androidx.camera.lifecycle.ProcessCameraProvider
import androidx.camera.view.PreviewView
import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.platform.LocalLifecycleOwner
import androidx.compose.ui.unit.dp
import androidx.compose.ui.viewinterop.AndroidView
import androidx.core.content.ContextCompat
import java.util.concurrent.ExecutorService
import java.util.concurrent.Executors

class InternalCameraActivity : ComponentActivity() {
    private lateinit var cameraExecutor: ExecutorService
    private var cameraControl: CameraControl? = null
    private var cameraInfo: CameraInfo? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        cameraExecutor = Executors.newSingleThreadExecutor()

        setContent {
            Surface(modifier = Modifier.fillMaxSize(), color = Color.Black) {
                CameraScreen()
            }
        }
    }

    @Composable
    fun CameraScreen() {
        val context = LocalContext.current
        val lifecycleOwner = LocalLifecycleOwner.current
        val previewView = remember { PreviewView(context) }
        var zoomRatio by remember { mutableStateOf(1f) }
        var hasCameraPermission by remember {
            mutableStateOf(
                ContextCompat.checkSelfPermission(context, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED
            )
        }

        val launcher = rememberLauncherForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            hasCameraPermission = isGranted
            if (!isGranted) {
                Toast.makeText(context, "Camera permission is required", Toast.LENGTH_SHORT).show()
                finish()
            }
        }

        LaunchedEffect(hasCameraPermission) {
            if (!hasCameraPermission) {
                launcher.launch(Manifest.permission.CAMERA)
                return@LaunchedEffect
            }

            val cameraProviderFuture = ProcessCameraProvider.getInstance(context)
            cameraProviderFuture.addListener({
                val cameraProvider = cameraProviderFuture.get()
                val preview = Preview.Builder().build().also {
                    it.setSurfaceProvider(previewView.surfaceProvider)
                }

                val selector = CameraSelector.DEFAULT_BACK_CAMERA

                try {
                    cameraProvider.unbindAll()
                    val camera = cameraProvider.bindToLifecycle(lifecycleOwner, selector, preview)
                    cameraControl = camera.cameraControl
                    cameraInfo = camera.cameraInfo

                    cameraInfo?.zoomState?.value?.let {
                        DebugLogger.log("CAM_X", "Zoom Range: ${it.minZoomRatio} to ${it.maxZoomRatio}")
                    }
                } catch (e: Exception) {
                    DebugLogger.log("CAM_X", "Binding failed: ${e.message}")
                }
            }, ContextCompat.getMainExecutor(context))
        }

        Box(modifier = Modifier.fillMaxSize()) {
            if (hasCameraPermission) {
                AndroidView(factory = { previewView }, modifier = Modifier.fillMaxSize())
            }

            Column(
                modifier = Modifier.align(Alignment.BottomCenter).padding(32.dp),
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Row(horizontalArrangement = Arrangement.spacedBy(16.dp)) {
                    Button(
                        onClick = {
                            val minZoom = cameraInfo?.zoomState?.value?.minZoomRatio ?: 1f
                            if (minZoom < 1f) {
                                cameraControl?.setZoomRatio(minZoom)
                                zoomRatio = minZoom
                                DebugLogger.log("CAM_X", "Wide Activated: $minZoom")
                            } else {
                                DebugLogger.log("CAM_X", "Hardware reported no logical wide lens")
                                Toast.makeText(context, "Wide lens not detected as logical unit", Toast.LENGTH_SHORT).show()
                            }
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = if (zoomRatio < 1f) Color.Cyan else Color.DarkGray)
                    ) { Text(".5") }

                    Button(
                        onClick = {
                            cameraControl?.setZoomRatio(1f)
                            zoomRatio = 1f
                        },
                        colors = ButtonDefaults.buttonColors(containerColor = if (zoomRatio == 1f) Color.Cyan else Color.DarkGray)
                    ) { Text("1x") }
                }

                Spacer(Modifier.height(16.dp))
                TextButton(onClick = { finish() }) { Text("CLOSE", color = Color.White) }
            }
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        cameraExecutor.shutdown()
    }
}

