fun bindCamera(selector: CameraSelector) {
    val cameraProviderFuture = ProcessCameraProvider.getInstance(context)
    cameraProviderFuture.addListener({
        val cameraProvider = cameraProviderFuture.get()

        // Discovery Logic: Only run once to find the Wide Lens
        if (wideCameraSelector == null) {
            val availableCameras = cameraProvider.availableCameraInfos
            DebugLogger.log("DISCOVERY", "Found ${availableCameras.size} sensors")

            var bestWideInfo: CameraInfo? = null
            var minFocal = 99f

            for (info in availableCameras) {
                val c2Info = Camera2CameraInfo.from(info)
                val focalLengths = c2Info.getCameraCharacteristic(android.hardware.camera2.CameraCharacteristics.LENS_INFO_AVAILABLE_FOCAL_LENGTHS)
                val focal = focalLengths?.firstOrNull() ?: 5f
                val id = c2Info.cameraId

                DebugLogger.log("SENSOR", "ID: $id | Focal: $focal mm")

                // On Android, ultra-wide focal length is usually < 3.0mm
                if (focal < minFocal) {
                    minFocal = focal
                    bestWideInfo = info
                }
            }

            if (minFocal < 3.0f && bestWideInfo != null) {
                wideCameraSelector = bestWideInfo.cameraSelector
                DebugLogger.log("DISCOVERY", "Identified Wide Lens at ID: ${Camera2CameraInfo.from(bestWideInfo).cameraId}")
            }
        }

        val preview = Preview.Builder().build().also {
            it.setSurfaceProvider(previewView.surfaceProvider)
        }

        try {
            cameraProvider.unbindAll()
            val camera = cameraProvider.bindToLifecycle(lifecycleOwner, selector, preview)
            cameraControl = camera.cameraControl
            cameraInfo = camera.cameraInfo
        } catch (e: Exception) {
            DebugLogger.log("CAM_X", "Binding failed: ${e.message}")
        }
    }, ContextCompat.getMainExecutor(context))
}

