        }
    }, null)
}

private fun startCalibration() {
    if (calibrationOverlay != null) return
    val wm = getSystemService(Context.WINDOW_SERVICE) as WindowManager

    // 1. Launch Camera first
    toggleCamera()

    // 2. Create Calibration UI
    val layout = android.widget.FrameLayout(this)

    // The Crosshair (Draggable)
    val crosshair = View(this).apply {
        setBackgroundColor(android.graphics.Color.RED)
        alpha = 0.5f
        layoutParams = android.widget.FrameLayout.LayoutParams(80, 80)
    }

    // The SET Button
    val setBtn = android.widget.Button(this).apply {
        text = "SET COORDS"
        setBackgroundColor(android.graphics.Color.BLACK)
        setTextColor(android.graphics.Color.WHITE)
    }

    layout.addView(crosshair)
    layout.addView(setBtn, android.widget.FrameLayout.LayoutParams(400, 150, android.view.Gravity.BOTTOM or android.view.Gravity.CENTER_HORIZONTAL).apply {
        bottomMargin = 300
    })

    val params = WindowManager.LayoutParams(
        WindowManager.LayoutParams.MATCH_PARENT,
        WindowManager.LayoutParams.MATCH_PARENT,
        WindowManager.LayoutParams.TYPE_ACCESSIBILITY_OVERLAY,
        WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE,
        PixelFormat.TRANSLUCENT
    )

    // Drag Logic
    crosshair.setOnTouchListener { v, event ->
        if (event.action == android.view.MotionEvent.ACTION_MOVE) {
            v.x = event.rawX - (v.width / 2)
            v.y = event.rawY - (v.height / 2)
        }
        true
    }

    setBtn.setOnClickListener {
        val finalX = crosshair.x + (crosshair.width / 2)
        val finalY = crosshair.y + (crosshair.height / 2)
        getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE).edit()
            .putFloat("calibrated_x", finalX)
            .putFloat("calibrated_y", finalY).apply()

        speak("Coordinates saved. Calibration complete.")
        wm.removeView(layout)
        calibrationOverlay = null
    }

    wm.addView(layout, params)
    calibrationOverlay = layout
    speak("Drag the red box over the point 5 button and tap set.")
}

private fun clickLensCoordinatesFallback() {
    val metrics = resources.displayMetrics
    injectPhysicalTap(metrics.widthPixels / 2f, metrics.heightPixels * 0.70f)
}

