        if (event.action == android.view.MotionEvent.ACTION_MOVE) {
            v.x = event.rawX - (v.width / 2)
            v.y = event.rawY - (v.height / 2)
        }
        true
    }

    setBtn.setOnClickListener {
        val finalX = crosshair.x + (crosshair.width / 2)
        val finalY = crosshair.y + (crosshair.height / 2)
        getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE).edit()
            .putFloat("calibrated_x", finalX)
            .putFloat("calibrated_y", finalY).apply()

        speak("Coordinates saved. Calibration complete.")
        wm.removeView(layout)
        calibrationOverlay = null
    }

    wm.addView(layout, params)
    calibrationOverlay = layout
    speak("Drag the red box over the point 5 button and tap set.")
}

