package com.eyecare.guard

import android.accessibilityservice.AccessibilityService
import android.content.BroadcastReceiver
import android.content.Intent
import android.content.IntentFilter
import android.graphics.Color
import android.view.Gravity
import android.view.WindowManager
import android.view.accessibility.AccessibilityEvent
import android.view.accessibility.AccessibilityNodeInfo
import android.widget.TextView
import kotlinx.coroutines.*

class EyeCareService : AccessibilityService() {

    private var isScreenActive = true
    private val screenReceiver = object : BroadcastReceiver() {
        override fun onReceive(context: android.content.Context, intent: Intent) {
            if (intent.action == Intent.ACTION_SCREEN_OFF) {
                isScreenActive = false
                TimeManager.lastScreenOffTs = System.currentTimeMillis()
                TimeManager.save(context)
            } else if (intent.action == Intent.ACTION_SCREEN_ON) {
                isScreenActive = true
                val now = System.currentTimeMillis()
                if (TimeManager.lastScreenOffTs > 0 && (now - TimeManager.lastScreenOffTs) > 5 * 60 * 1000L) {
                    TimeManager.resetContinuous(context)
                }
                TimeManager.sessionStart = now
            }
        }
    }

    private val job = SupervisorJob()
    private val scope = CoroutineScope(Dispatchers.Main + job)

    private var timerJob: Job? = null
    private var warningView: TextView? = null
    private var windowManager: WindowManager? = null
    private var currentPackage: String = ""

    // SECURITY STATE
    // VerifiedSafe prevents blocking innocent apps if we clearly saw their name.
    // If null/false, we assume ANY danger button is a threat.
    private var verifiedSafeSessionPackage: String? = null

    // Warning States
    private var sleepWarn15 = false
    private var sleepWarn5 = false
    private var sleepWarn1 = false
    private var longWarn5 = false
    private var longWarn1 = false
    private var medWarn1 = false

    override fun onServiceConnected() {
        super.onServiceConnected()
        val channelId = "eyecare_min_channel"
        val nm = getSystemService(android.app.NotificationManager::class.java)
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            val chan = android.app.NotificationChannel(channelId, "Monitor", android.app.NotificationManager.IMPORTANCE_MIN)
            chan.setShowBadge(false)
            nm.createNotificationChannel(chan)
        }
        val notif = androidx.core.app.NotificationCompat.Builder(this, channelId)
            .setContentTitle("Eyecare")
            .setContentText("Active")
            .setSmallIcon(android.R.drawable.ic_menu_view)
            .setPriority(androidx.core.app.NotificationCompat.PRIORITY_MIN)
            .setCategory(androidx.core.app.NotificationCompat.CATEGORY_SERVICE)
            .setOngoing(true)
            .build()
        startForeground(2024, notif)

        StatsManager.init(this)
        TimeManager.init(this)
        windowManager = getSystemService(WindowManager::class.java)
        TimeManager.sessionStart = System.currentTimeMillis()

        val filter = IntentFilter().apply {
            addAction(Intent.ACTION_SCREEN_ON)
            addAction(Intent.ACTION_SCREEN_OFF)
        }
        registerReceiver(screenReceiver, filter)

        startTimerLoop()
        startMonitoring()
    }

    override fun onAccessibilityEvent(event: AccessibilityEvent?) {
        if (event == null) return
        val pkg = event.packageName?.toString() ?: ""

        if (pkg == packageName) return
        if (NukeManager.isProtectionDisabled(this)) return

        if (event.eventType == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
            verifiedSafeSessionPackage = null
            currentPackage = pkg
        }

        // --- HIGH ALERT ZONES ---
        // Settings, Installer, Permission Controller
        if (pkg.contains("settings") || pkg.contains("packageinstaller") || pkg.contains("google.android.permissioncontroller")) {
            handleSecurityZone(event)
        }
    }

    private fun handleSecurityZone(event: AccessibilityEvent) {
        val root = rootInActiveWindow ?: return 

        // 1. SCAN CONTENT
        val allText = StringBuilder()
        val nodeList = ArrayList<AccessibilityNodeInfo>()
        scanNodeRecursively(root, allText, nodeList)
        val content = allText.toString().lowercase()

        // 2. IDENTIFY THREATS
        val hasDangerButtons = content.contains("force stop") || 
                               content.contains("uninstall") || 
                               content.contains("disable") || 
                               content.contains("clear storage")

        // 3. DIALOG TRAP
        // If a dialog appears in Settings (e.g. "Do you want to uninstall?") and we haven't 
        // explicitly verified we are in a safe app session, we panic.
        val isDialog = event.className?.contains("Dialog") == true || event.className?.contains("Alert") == true
        if (isDialog) {
            if (verifiedSafeSessionPackage == null) {
                DebugLogger.log("SECURITY", "Ambiguous Dialog detected. Blocking.")
                performMachineGun()
                return
            }
        }

        // 4. PARANOID CHECK
        if (hasDangerButtons) {
            // A. Guilty Evidence
            if (content.contains("eyecare")) {
                performMachineGun()
                return
            }

            // B. Ambiguity Check
            // If we see danger buttons but NO safe app name is confirmed, we assume it's Eyecare hidden by scrolling.
            val isSafe = checkIfSafeContext(content)
            if (isSafe) {
                verifiedSafeSessionPackage = "SAFE"
            } else {
                // Ambiguous = Threat
                DebugLogger.log("SECURITY", "Ambiguous Threat (No Safe Anchor). Blocking.")
                performMachineGun()
            }
        }
    }

    private fun checkIfSafeContext(content: String): Boolean {
        // STRICT MODE: To fix the vulnerability, we return FALSE by default.
        // This means ANY 'Force Stop' screen that doesn't clearly identify itself as innocent will be blocked.
        // If you want to allow specific apps, add them here carefully.
        // Example: if (content.contains("youtube")) return true
        return false
    }

    private fun performMachineGun() {
        // 1. RAPID FIRE BACK
        repeat(4) {
            performGlobalAction(GLOBAL_ACTION_BACK)
        }

        // 2. VISUAL SHIELD (Blocks clicks if Back fails)
        val i = Intent(applicationContext, LockdownActivity::class.java)
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_ANIMATION or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        i.putExtra("BLOCK_TYPE", "SECURITY_TRIPWIRE")
        startActivity(i)

        // 3. NUCLEAR EXIT (Go Home)
        val home = Intent(Intent.ACTION_MAIN)
        home.addCategory(Intent.CATEGORY_HOME)
        home.flags = Intent.FLAG_ACTIVITY_NEW_TASK
        startActivity(home)
    }

    private fun scanNodeRecursively(node: AccessibilityNodeInfo?, sb: StringBuilder, list: MutableList<AccessibilityNodeInfo>) {
        if (node == null) return
        list.add(node)
        if (node.text != null) sb.append(node.text).append(" ")
        if (node.contentDescription != null) sb.append(node.contentDescription).append(" ")
        val count = node.childCount
        for (i in 0 until count) {
            scanNodeRecursively(node.getChild(i), sb, list)
        }
    }

