                        cls.contains("appmanagement") || 
                        hasAppInfoHeader || 
                        (hasUninstall && hasForceStop)

    var confirmedDanger = false

    // MULTI-WINDOW DEFENSE: Content Scanning
    val allWindows = this.windows
    if (!allWindows.isEmpty()) {
        for (window in allWindows) {
            val root = window.root ?: continue

            // GLOBAL SCAN: Locate identifying strings first
            // We look for the App Name "Guardian" to detect our own App Info page
            val hasDnsGuard = root.findAccessibilityNodeInfosByText("Guardian")

            // A. ACCESSIBILITY TRAP (Targeted)
            val trap1 = root.findAccessibilityNodeInfosByText("Monitors system settings")
            val trap2 = root.findAccessibilityNodeInfosByText("enforce Private DNS")

            if (trap1.isNotEmpty() || trap2.isNotEmpty()) {
                confirmedDanger = true
                performGlobalAction(GLOBAL_ACTION_BACK)
                startTripwire()
                break
            }

            // B. DEVICE ADMIN TRAP
            val hasDeactivate = root.findAccessibilityNodeInfosByText("Deactivate")
            if (hasDeactivate.isNotEmpty() && hasDnsGuard.isNotEmpty()) {
                 confirmedDanger = true
                 performGlobalAction(GLOBAL_ACTION_BACK)
                 startTripwire()
                 break
            }

            // C. SELF-DEFENSE (App Info & Storage Guard)
            if (isAppInfoPage) {
                val nodePkg = root.packageName?.toString() ?: ""
                val isSettingsWindow = nodePkg.contains("settings") || nodePkg.contains("packageinstaller")

                if (isSettingsWindow && hasDnsGuard.isNotEmpty()) {
                    confirmedDanger = true
                    performGlobalAction(GLOBAL_ACTION_BACK)
                    startTripwire()
                    break
                }
            }
        }
    }

    // VERDICT: THREAT CONFIRMED
    if (confirmedDanger) {
        // CASE 1: THREAT CONFIRMED -> LOCKDOWN ACTIVITY ONLY (No Back Press)
        DebugLogger.log("BLOCK", "Threat Confirmed! Launching Tripwire.")
        shieldJob?.cancel()
        startTripwire()
    } else if (isAppInfoPage) {
        DebugLogger.log("Check", "AppInfoPage Detected. VerifiedSession: $verifiedSafeAppInfoSession")
        // CASE 2: APP INFO PAGE (Ambiguous)
        shieldJob?.cancel()

        // VERIFICATION: Enhanced Anchor List
        // We check for MULTIPLE standard elements. If ANY are found, we assume it's a standard App Info page.
        // This prevents false positives when "Notifications" is missing or named differently.
        val safeAnchors = listOf(
            "Notifications", "Permissions", "Storage", "Battery", 
            "Data usage", "Open", "Uninstall", "Force stop"
        )

        val currentRoot = rootInActiveWindow
        var hasAnchor = false
        if (currentRoot != null) {
             hasAnchor = safeAnchors.any { 
                 currentRoot.findAccessibilityNodeInfosByText(it)?.isNotEmpty() == true 
             }
        }

        DebugLogger.log("Check", "Safe Anchor Found: $hasAnchor")

        if (verifiedSafeAppInfoSession) {
            DebugLogger.log("Allow", "Session previously verified. Scrolling allowed.")
        } else if (hasAnchor) {
            DebugLogger.log("Allow", "Anchor found. Marking session verified.")
            verifiedSafeAppInfoSession = true
        } else {
            DebugLogger.log("BLOCK", "KICK OUT! No known anchors found. Machine Gun Active.")
            // CASE 3: HIDDEN/SCROLLED AWAY -> KICK OUT
            // If we see an "App Info" page but NONE of the standard buttons, assume it is malicious or modified.
            scope.launch {
                repeat(4) {
                    performGlobalAction(GLOBAL_ACTION_BACK)
                    delay(100)
                }
            }
        }
    } else {
        // CASE 4: GENERAL SETTINGS / MENU
        shieldJob?.cancel()

        // SAFE RESET: Only reset if we POSITIVELY see the main Settings header.
        val root = rootInActiveWindow
        val hasSettingsHeader = root?.findAccessibilityNodeInfosByText("Settings")?.isNotEmpty() == true
        val hasSearchHeader = root?.findAccessibilityNodeInfosByText("Search settings")?.isNotEmpty() == true

        if (hasSettingsHeader || hasSearchHeader) {
            if (verifiedSafeAppInfoSession) {
                 DebugLogger.log("Reset", "Back in Main Settings. Session Invalidated.")
                 verifiedSafeAppInfoSession = false
            }
        }
    }
}

