import android.accessibilityservice.AccessibilityService
import android.content.BroadcastReceiver
import android.content.Intent
import android.content.IntentFilter
import android.graphics.Color
import android.view.Gravity
import android.view.WindowManager
import android.view.accessibility.AccessibilityEvent
import android.view.accessibility.AccessibilityNodeInfo
import android.widget.TextView
import kotlinx.coroutines.*

class EyeCareService : AccessibilityService() {

    private var isScreenActive = true
    private val screenReceiver = object : BroadcastReceiver() {
        override fun onReceive(context: android.content.Context, intent: Intent) {
            if (intent.action == Intent.ACTION_SCREEN_OFF) {
                isScreenActive = false
                TimeManager.lastScreenOffTs = System.currentTimeMillis()
                TimeManager.save(context)
            } else if (intent.action == Intent.ACTION_SCREEN_ON) {
                isScreenActive = true
                val now = System.currentTimeMillis()
                if (TimeManager.lastScreenOffTs > 0 && (now - TimeManager.lastScreenOffTs) > 5 * 60 * 1000L) {
                    TimeManager.resetContinuous(context)
                }
                TimeManager.sessionStart = now
            }
        }
    }

    private val job = SupervisorJob()
    private val scope = CoroutineScope(Dispatchers.Main + job)

    private var timerJob: Job? = null
    private var warningView: TextView? = null
    private var windowManager: WindowManager? = null
    private var currentPackage: String = ""

    // SECURITY STATE
    // verifiedSafeSessionPackage: "SAFE" if we have seen safe Anchors (Notifications, Storage) in this session.
    // Resets to null on every window state change.
    private var verifiedSafeSessionPackage: String? = null

    // Warning States
    private var sleepWarn15 = false
    private var sleepWarn5 = false
    private var sleepWarn1 = false
    private var longWarn5 = false
    private var longWarn1 = false
    private var medWarn1 = false

    override fun onServiceConnected() {
        super.onServiceConnected()
        val channelId = "eyecare_min_channel"
        val nm = getSystemService(android.app.NotificationManager::class.java)
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            val chan = android.app.NotificationChannel(channelId, "Monitor", android.app.NotificationManager.IMPORTANCE_MIN)
            chan.setShowBadge(false)
            nm.createNotificationChannel(chan)
        }
        val notif = androidx.core.app.NotificationCompat.Builder(this, channelId)
            .setContentTitle("Eyecare")
            .setContentText("Active")
            .setSmallIcon(android.R.drawable.ic_menu_view)
            .setPriority(androidx.core.app.NotificationCompat.PRIORITY_MIN)
            .setCategory(androidx.core.app.NotificationCompat.CATEGORY_SERVICE)
            .setOngoing(true)
            .build()
        startForeground(2024, notif)

        StatsManager.init(this)
        TimeManager.init(this)
        windowManager = getSystemService(WindowManager::class.java)
        TimeManager.sessionStart = System.currentTimeMillis()

        val filter = IntentFilter().apply {
            addAction(Intent.ACTION_SCREEN_ON)
            addAction(Intent.ACTION_SCREEN_OFF)
        }
        registerReceiver(screenReceiver, filter)

        startTimerLoop()
        startMonitoring()
    }

    override fun onAccessibilityEvent(event: AccessibilityEvent?) {
        if (event == null) return
        val pkg = event.packageName?.toString() ?: ""

        if (pkg == packageName) return
        if (NukeManager.isProtectionDisabled(this)) return

        // RESET Verification on Window Change
        if (event.eventType == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
            verifiedSafeSessionPackage = null
            currentPackage = pkg
        }

        // --- HIGH ALERT ZONES ---
        // Settings, Installer, Permission Controller, Accessibility
        if (pkg.contains("settings") || 
            pkg.contains("packageinstaller") || 
            pkg.contains("google.android.permissioncontroller") ||
            pkg.contains("accessibility")) {
            handleSecurityZone(event)
        }
    }

    private fun handleSecurityZone(event: AccessibilityEvent) {
        val root = rootInActiveWindow ?: return 

        // 1. DIALOG TRAP (Zero-Trust)
        // If a Dialog/Alert appears in Settings and we haven't VERIFIED the session with anchors,
        // we assume it is an uninstall/force-stop confirmation -> MACHINE GUN.
        val isDialog = event.className?.contains("Dialog") == true || event.className?.contains("Alert") == true
        if (isDialog) {
            if (verifiedSafeSessionPackage == null) {
                DebugLogger.log("SECURITY", "Unverified Dialog in Settings. Machine Gun.")
                performMachineGun()
                return
            }
        }

        // 2. CONTENT SCAN
        val allText = StringBuilder()
        val nodeList = ArrayList<AccessibilityNodeInfo>()
        scanNodeRecursively(root, allText, nodeList)
        val content = allText.toString()
        val lowerContent = content.lowercase()

        // 3. THREAT IDENTIFICATION
        // Trigger on Danger Buttons
        val hasDangerButtons = lowerContent.contains("force stop") || 
                               lowerContent.contains("uninstall") || 
                               lowerContent.contains("disable") || 
                               lowerContent.contains("clear storage")

        if (hasDangerButtons) {
            // A. GUILTY: We see our name
            if (lowerContent.contains("eyecare")) {
                performMachineGun()
                return
            }

            // B. ANCHOR VERIFICATION (The "Safe" Proof)
            // If we are looking at a valid App Info page for another app, we expect standard UI elements.
            // If these are missing (because of scrolling or malicious UI), we do NOT trust it.
            val anchors = listOf(
                "Notifications", "Permissions", "Storage", 
                "Data usage", "Battery", "Open", "Defaults"
            )

            var hasAnchor = false
            for (anchor in anchors) {
                if (content.contains(anchor, ignoreCase = true)) {
                    hasAnchor = true
                    break
                }
            }

            if (hasAnchor) {
                // SAFE: We see "Force Stop" + "Storage/Permissions" + NO "Eyecare". 
                // This is a normal App Info page for another app.
                verifiedSafeSessionPackage = "SAFE"
            } else {
                // C. AMBIGUITY (The Gap)
                // We see "Force Stop" but NO Anchors.
                // This happens if user scrolls fast (hiding the body) or if it's a trap.
                // ACTION: BLOCK.
                if (verifiedSafeSessionPackage == null) {
                    DebugLogger.log("SECURITY", "Danger Button without Anchors. Ambiguous Threat. Blocking.")
                    performMachineGun()
                }
            }
        }
    }

    private fun performMachineGun() {
        // 1. RAPID FIRE BACK
        repeat(4) {
            performGlobalAction(GLOBAL_ACTION_BACK)
        }

        // 2. VISUAL SHIELD (Blocks clicks if Back fails)
        val i = Intent(applicationContext, LockdownActivity::class.java)
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_ANIMATION or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        i.putExtra("BLOCK_TYPE", "SECURITY_TRIPWIRE")
        startActivity(i)

        // 3. NUCLEAR EXIT (Go Home)
        val home = Intent(Intent.ACTION_MAIN)
        home.addCategory(Intent.CATEGORY_HOME)
        home.flags = Intent.FLAG_ACTIVITY_NEW_TASK
        startActivity(home)
    }

    private fun scanNodeRecursively(node: AccessibilityNodeInfo?, sb: StringBuilder, list: MutableList<AccessibilityNodeInfo>) {
        if (node == null) return
        list.add(node)
        if (node.text != null) sb.append(node.text).append(" ")
        if (node.contentDescription != null) sb.append(node.contentDescription).append(" ")
        val count = node.childCount
        for (i in 0 until count) {
            scanNodeRecursively(node.getChild(i), sb, list)
        }
    }

    private fun startMonitoring() {
        scope.launch {
            while (isActive) {
                // DETECT CONTEXT: Are we inside Settings?
                val inSettings = currentPackage.contains("settings") || 
                                 currentPackage.contains("accessibility") || 
                                 currentPackage.contains("packageinstaller")

                // 1. CHECK OVERLAY PERMISSION
                // CRITICAL FIX: Only enforce when OUTSIDE Settings to prevent permission loop.
                val hasOverlay = android.provider.Settings.canDrawOverlays(applicationContext)

                if (!hasOverlay && !inSettings) {
                    val i = Intent(android.provider.Settings.ACTION_MANAGE_OVERLAY_PERMISSION)
                    i.data = android.net.Uri.parse("package:$packageName")
                    i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                    startActivity(i)
                } else {
                    // 2. SECONDARY CHECKS
                    if (hasOverlay && !inSettings) {
                         checkSecondaryIntegrity()
                    }
                }
                StatsManager.update(applicationContext)
                delay(2000)
            }
        }
    }

    private fun checkSecondaryIntegrity() {
        val isAutoTime = android.provider.Settings.Global.getInt(contentResolver, android.provider.Settings.Global.AUTO_TIME, 0) == 1
        val isAutoZone = android.provider.Settings.Global.getInt(contentResolver, android.provider.Settings.Global.AUTO_TIME_ZONE, 0) == 1
        if (!isAutoTime || !isAutoZone) {
            val i = Intent(android.provider.Settings.ACTION_DATE_SETTINGS)
            i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
            startActivity(i)
            return
        }
    }

    private fun startTimerLoop() {
        timerJob = scope.launch {
            while (isActive) {
                delay(5000)
                if (isScreenActive) {
                    updateUsage()
                    checkRules()
                    if (TimeManager.accumulatedDailyMs % 300_000L < 5000) {
                        TimeManager.save(this@EyeCareService)
                    }
                }
            }
        }
    }

    private fun updateUsage() {
        val now = System.currentTimeMillis()
        val diff = now - TimeManager.sessionStart
        TimeManager.sessionStart = now
        TimeManager.continuousUsage += diff
        TimeManager.accumulatedDailyMs += diff
        if (TimeManager.accumulatedDailyMs % 60000 < 2000) {
            TimeManager.save(this)
        }
    }

    private suspend fun checkRules() {
        if (isCriticalAppForeground()) {
             hideBanner()
             return
        }
        val remainingLockout = TimeManager.getLockoutRemaining(this)
        if (remainingLockout > 0) {
             triggerBreak("MANUAL_LOCKOUT", remainingLockout)
             return
        }
        if (System.currentTimeMillis() < TimeManager.snoozeUntil) {
             hideBanner()
             return
        }

        val usage = TimeManager.continuousUsage
        val cal = java.util.Calendar.getInstance()
        val hour = cal.get(java.util.Calendar.HOUR_OF_DAY)
        val minute = cal.get(java.util.Calendar.MINUTE)
        val currentMs = (hour * 60 + minute) * 60 * 1000L + cal.get(java.util.Calendar.SECOND) * 1000L
        val target11PM = 23 * 60 * 60 * 1000L

        if (hour >= 23 || hour < 5) {
             hideBanner()
             triggerBreak("SLEEP_MODE", 0)
             return
        }

        val msToSleep = target11PM - currentMs
        if (msToSleep in 1..15 * 60 * 1000) {
             handleSleepWarnings(msToSleep)
        }

        if (TimeManager.nextLongBreak - usage <= 5 * 60 * 1000) {
             handleLongBreakWarnings(TimeManager.nextLongBreak - usage)
             return
        }
        if (TimeManager.nextMediumBreak - usage <= 60 * 1000) {
             handleMediumBreakWarnings(TimeManager.nextMediumBreak - usage)
             return
        }
        if (TimeManager.nextShortBreak - usage <= 10 * 1000) {
             handleShortBreakCountdown(TimeManager.nextShortBreak - usage)
        }
    }

    private suspend fun handleSleepWarnings(remaining: Long) {
        if (remaining <= 10_000) {
             runCountdown("Sleep Mode", remaining)
             triggerBreak("SLEEP_MODE", 0)
             return
        }
        if (remaining <= 60_000) {
            if (!sleepWarn1) {
                showBanner("Sleep Mode in 1 Minute")
                sleepWarn1 = true
            }
            return
        }
        if (remaining <= 5 * 60_000) {
            if (!sleepWarn5) {
                showBanner("Sleep Mode in 5 Minutes")
                sleepWarn5 = true
            }
            return
        }
        if (remaining <= 15 * 60_000) {
            if (!sleepWarn15) {
                showBanner("Sleep Mode in 15 Minutes")
                sleepWarn15 = true
            }
        }
    }

    private suspend fun handleLongBreakWarnings(remaining: Long) {
        if (remaining <= 10_000) {
             runCountdown("15m Break", remaining)
             triggerBreak("EXTENDED", 15 * 60 * 1000L)
             TimeManager.nextLongBreak += TimeManager.INTERVAL_3_HOUR
             return
        }
        if (remaining <= 60_000) {
             if (!longWarn1) {
                 showBanner("Long Break in 1 Minute")
                 longWarn1 = true
             }
             return
        }
        if (remaining <= 5 * 60_000) {
             if (!longWarn5) {
                 showBanner("Long Break in 5 Minutes")
                 longWarn5 = true
             }
        }
    }

    private suspend fun handleMediumBreakWarnings(remaining: Long) {
        if (remaining <= 10_000) {
             runCountdown("5m Break", remaining)
             triggerBreak("LONG", 5 * 60 * 1000L)
             TimeManager.nextMediumBreak += TimeManager.INTERVAL_60_MIN
             medWarn1 = false
             return
        }
        if (remaining <= 60_000) {
             if (!medWarn1) {
                 showBanner("5m Break in 1 Minute")
                 medWarn1 = true
             }
        }
    }

    private suspend fun handleShortBreakCountdown(remaining: Long) {
        if (remaining <= 10_000) {
             runCountdown("Rest", remaining)
             triggerBreak("SHORT", 30 * 1000L)
             TimeManager.nextShortBreak += TimeManager.INTERVAL_30_MIN
        }
    }

    private suspend fun runCountdown(title: String, startMs: Long) {
        var ms = startMs
        while (ms > 0) {
            showBanner("$title in ${ms/1000}...")
            delay(1000)
            ms -= 1000
        }
        hideBanner()
    }

    private fun isCriticalAppForeground(): Boolean {
        val safeApps = setOf(
            "com.google.android.apps.maps", "com.waze", "com.yandex.yandexmaps",
            "com.google.android.dialer", "com.samsung.android.dialer", "com.android.server.telecom", 
            "us.zoom.videomeetings", "com.microsoft.teams", "com.skype.raider",
            "com.ubercab", "me.lyft.android",
            "com.android.camera", "com.sec.android.app.camera", "com.google.android.GoogleCamera"
        )
        val lowerPkg = currentPackage.lowercase()
        return safeApps.contains(currentPackage) || 
               lowerPkg.contains("maps") || 
               lowerPkg.contains("dialer") ||
               lowerPkg.contains("call") ||
               lowerPkg.contains("camera") ||
               lowerPkg.contains("incallui")
    }

    private fun triggerBreak(type: String, duration: Long) {
        val i = Intent(this, BreakActivity::class.java)
        i.putExtra("TYPE", type)
        i.putExtra("DURATION", duration)
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_ANIMATION or Intent.FLAG_ACTIVITY_REORDER_TO_FRONT)
        startActivity(i)
    }

    private fun showBanner(text: String) {
        try {
            if (warningView == null) {
                val container = android.widget.LinearLayout(this).apply {
                    orientation = android.widget.LinearLayout.VERTICAL
                    setPadding(40, 40, 40, 40)
                    gravity = Gravity.CENTER
                }

                val card = android.widget.TextView(this).apply {
                    setTextColor(Color.WHITE)
                    textSize = 16f
                    typeface = android.graphics.Typeface.DEFAULT_BOLD
                    gravity = Gravity.CENTER
                    setPadding(60, 30, 60, 30)
                    elevation = 20f
                    background = android.graphics.drawable.GradientDrawable().apply {
                         shape = android.graphics.drawable.GradientDrawable.RECTANGLE
                         setColor(Color.parseColor("#CC111111"))
                         cornerRadius = 50f
                         setStroke(2, Color.parseColor("#00E676"))
                    }
                }

                container.addView(card)
                warningView = card
                warningView?.tag = container

                val params = WindowManager.LayoutParams(
                    WindowManager.LayoutParams.MATCH_PARENT,
                    WindowManager.LayoutParams.WRAP_CONTENT,
                    WindowManager.LayoutParams.TYPE_ACCESSIBILITY_OVERLAY,
                    WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or WindowManager.LayoutParams.FLAG_LAYOUT_IN_SCREEN,
                    android.graphics.PixelFormat.TRANSLUCENT
                )
                params.gravity = Gravity.TOP
                params.y = 50

                windowManager?.addView(container, params)
            }

            warningView?.text = text

            if (!text.contains("...")) {
                 timerJob?.invokeOnCompletion {  }
                 scope.launch {
                     delay(5000)
                     if (warningView != null && warningView?.text == text) {
                        hideBanner()
                     }
                 }
            }
        } catch (e: Exception) { e.printStackTrace() }
    }

    private fun hideBanner() {
        try {
            if (warningView != null) {
                val container = warningView?.tag as? android.view.View
                if (container != null && container.parent != null) {
                    windowManager?.removeView(container)
                }
                warningView = null
            }
        } catch (e: Exception) { e.printStackTrace() }
    }

    override fun onInterrupt() {}

    override fun onDestroy() {
        super.onDestroy()
        try {
            unregisterReceiver(screenReceiver)
        } catch (e: Exception) { e.printStackTrace() }
    }
