    val currentWeek = cal2.get(Calendar.WEEK_OF_YEAR)
    if (lastWeekYear != currentWeek) {
        nightPassesLeft = 3
        lastWeekYear = currentWeek
    } else {
        nightPassesLeft = prefs.getInt(KEY_NIGHT_PASSES, 3)
    }

    isNightPassScheduled = prefs.getString(KEY_NIGHT_SCHEDULED, "FALSE") == "TRUE"

    // Daily Reset Logic
    if (cal1.get(Calendar.DAY_OF_YEAR) != cal2.get(Calendar.DAY_OF_YEAR)) {
        // If Night Pass is active AND it's before 5 AM, do NOT reset usage (Carry Debt)
        if (isNightPassScheduled && hour < 5) {
            accumulatedDailyMs = prefs.getLong(KEY_DAILY_MS, 0L)
        } else {
            accumulatedDailyMs = 0
            isNightPassScheduled = false // Pass expires at 5 AM or start of day
        }
