        startForegroundService()
        StatsManager.init(this)
        TimeManager.init(this)
        windowManager = getSystemService(WindowManager::class.java)
        TimeManager.sessionStart = System.currentTimeMillis()

        val filter = IntentFilter().apply {
            addAction(Intent.ACTION_SCREEN_ON)
            addAction(Intent.ACTION_SCREEN_OFF)
        }
        registerReceiver(screenReceiver, filter)

        runGuardianLoop()
    }

    private fun startForegroundService() {
        val channelId = "eyecare_min_channel"
        val nm = getSystemService(android.app.NotificationManager::class.java)
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            val chan = android.app.NotificationChannel(
                channelId,
                "Monitor",
                android.app.NotificationManager.IMPORTANCE_MIN
            )
            chan.setShowBadge(false)
            nm.createNotificationChannel(chan)
        }
        val notif = androidx.core.app.NotificationCompat.Builder(this, channelId)
            .setContentTitle("Eyecare")
            .setContentText("Active")
            .setSmallIcon(android.R.drawable.ic_menu_view)
            .setPriority(androidx.core.app.NotificationCompat.PRIORITY_MIN)
            .setCategory(androidx.core.app.NotificationCompat.CATEGORY_SERVICE)
            .setOngoing(true)
            .build()
        startForeground(2024, notif)
    }

    override fun onAccessibilityEvent(event: AccessibilityEvent?) {
        if (event == null) return
        val pkg = event.packageName?.toString() ?: ""
        val className = event.className?.toString() ?: ""
        val type = event.eventType

        if (pkg == packageName) return
        if (NukeManager.isProtectionDisabled(this)) return

        // 1. CONTEXT TRACKING & SPEED TRAP INITIALIZATION
        if (type == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
            verifiedSafeAppInfoSession = false // Reset freeze on window change
            currentPackage = pkg

            // SPEED TRAP: Start Stopwatch when entering Settings
            if (pkg.contains("settings") || pkg.contains("accessibility")) {
                entryTimestamp = System.currentTimeMillis()
            }

            // BLIND DIALOG KILLER (Context Memory)
            // If we came from a danger zone and see a dialog -> KILL.
            if (wasInDangerZone && (className.contains("Dialog") || className.contains("AlertDialog"))) {
                DebugLogger.log("SECURITY", "Blind Kill: Dialog detected after Danger Zone.")
                machineGun()
                return
            }

            // Update Danger Zone Status
            // We are 'Dangerous' if in Settings, Accessibility, or Package Installer
            wasInDangerZone = pkg.contains("settings") || pkg.contains("accessibility") || pkg.contains("packageinstaller")
            lastWindowPkg = pkg
        }

        val root = rootInActiveWindow ?: return

        // 2. SETTINGS DEFENSE
        if (pkg.contains("settings") || pkg.contains("accessibility") || pkg.contains("packageinstaller") || pkg.contains("systemui")) {

            // A. SPEED TRAP ENFORCEMENT (The 1-Second Rule)
            // If user Clicks or Scrolls within 1 second of entering -> KILL
            if (type == AccessibilityEvent.TYPE_VIEW_CLICKED || type == AccessibilityEvent.TYPE_VIEW_SCROLLED) {
                val timeDiff = System.currentTimeMillis() - entryTimestamp
                if (timeDiff < 1000) {
                    DebugLogger.log("SECURITY", "Speed Trap: Interaction in ${timeDiff}ms. Blocked.")
                    machineGun()
                    return
                }
            }

            // B. THE TRINITY CHECK (Fixing the Toggle Exploit)
            // We check for 3 Cores: NAME + DESCRIPTION + STATUS
            val hasName = root.findAccessibilityNodeInfosByText("Eyecare").isNotEmpty()
            if (hasName) {
                val descriptionText = getString(R.string.accessibility_desc)
                val hasDescription = root.findAccessibilityNodeInfosByText(descriptionText).isNotEmpty()

                if (hasDescription) {
                    // We are in the Specific Toggle Screen. Now check Status.
                    val switchNode = findSwitch(root)
                    val isChecked = switchNode?.isChecked == true

                    if (isChecked) {
                        // Trinity Complete: Name + Desc + ON -> User is trying to Turn OFF.
                        DebugLogger.log("SECURITY", "Trinity Violation: Attempt to disable service.")
                        machineGun()
                        return
                    }
                    // If isChecked is FALSE, we allow it (User is trying to Enable).
                }
            }

            // C. APP INFO FREEZE (Fixing the Scroll Exploit)
            val hasUninstall = root.findAccessibilityNodeInfosByText("Uninstall").isNotEmpty()
            val hasForceStop = root.findAccessibilityNodeInfosByText("Force stop").isNotEmpty() || 
                               root.findAccessibilityNodeInfosByText("FORCE STOP").isNotEmpty()

            if (hasUninstall && hasForceStop) {
                // We are in an App Info Page.
                if (hasName) {
                     // It's OUR App Info Page. KILL.
                     machineGun()
                     startTripwire()
                     return
                }

                // It's ANOTHER App Info Page.
                // CHECK: Is it verified safe?
                if (!verifiedSafeAppInfoSession) {
                    // FREEZE STATE: Look for Safe Anchors
                    val isSafe = root.findAccessibilityNodeInfosByText("Permissions").isNotEmpty() || 
                                 root.findAccessibilityNodeInfosByText("Notifications").isNotEmpty() ||
                                 root.findAccessibilityNodeInfosByText("Storage").isNotEmpty()

                    if (isSafe) {
                        verifiedSafeAppInfoSession = true
                    } else {
                        // STILL FROZEN: If user interacts -> KILL
                        if (type == AccessibilityEvent.TYPE_VIEW_CLICKED || type == AccessibilityEvent.TYPE_VIEW_SCROLLED) {
                            DebugLogger.log("SECURITY", "Freeze Violation: Interaction on unverified page.")
                            machineGun()
                        }
                    }
                }
            }
        }

        // 3. DIALOG TRAP (Text Reader - Fallback)
        if (className.contains("Dialog") || className.contains("popup", ignoreCase = true)) {
            val sb = StringBuilder()
            recursiveScan(root, sb)
            val text = sb.toString()

            val isTargetingUs = text.contains("Eyecare", ignoreCase = true)
            val isDestructive = text.contains("Stop", ignoreCase = true) || 
                                text.contains("Turn off", ignoreCase = true) ||
                                text.contains("Deactivate", ignoreCase = true)

            if (isTargetingUs && isDestructive) {
                DebugLogger.log("SECURITY", "Dialog Trap: Destructive text detected.")
                machineGun()
            }
        }
