fun TemporalControlsCard() {
    var lockMinutes by remember { mutableStateOf("") }
    var showNightPassWarning by remember { mutableStateOf(false) }

    val currentHour = java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY)
    val isDuskToDawn = currentHour >= 18 || currentHour < 6
    val canUseNightPass = !isDuskToDawn && TimeManager.nightPassUsedThisWeek < 3 && !TimeManager.isNightPassScheduled

    Card(
        colors = CardDefaults.cardColors(containerColor = Color(0xFF1A1C1E)),
        modifier = Modifier.fillMaxWidth()
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text("FOCUS & HEALTH", style = MaterialTheme.typography.labelLarge, color = Color(0xFF39CCCC))
            Spacer(modifier = Modifier.height(12.dp))

            // LOCK ME OUT SECTION
            Row(verticalAlignment = Alignment.CenterVertically) {
                OutlinedTextField(
                    value = lockMinutes,
                    onValueChange = { if (it.length <= 3) lockMinutes = it.filter { c -> c.isDigit() } },
                    label = { Text("Mins", fontSize = 12.sp) },
                    modifier = Modifier.width(100.dp),
                    singleLine = true,
                    keyboardOptions = androidx.compose.foundation.text.KeyboardOptions(keyboardType = androidx.compose.ui.text.input.KeyboardType.Number)
                )
                Spacer(modifier = Modifier.width(8.dp))
                Button(
                    onClick = {
                        val mins = lockMinutes.toIntOrNull() ?: 0
                        if (mins > 0) {
                            TimeManager.setManualLockout(applicationContext, mins)
                        }
                    },
                    modifier = Modifier.weight(1f),
                    shape = RoundedCornerShape(8.dp),
                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFFF012BE))
                ) {
                    Text("LOCK ME OUT")
                }
            }

            Spacer(modifier = Modifier.height(16.dp))
            Divider(color = Color.DarkGray)
            Spacer(modifier = Modifier.height(16.dp))

            // NIGHT PASS SECTION
            Row(verticalAlignment = Alignment.CenterVertically) {
                Column(modifier = Modifier.weight(1f)) {
                    Text("Night Pass", color = Color.White, fontWeight = FontWeight.Bold)
                    Text(
                        if (isDuskToDawn) "Disabled until 06:00" else "${3 - TimeManager.nightPassUsedThisWeek} remaining this week",
                        color = if (isDuskToDawn) Color.Red else Color.Gray, 
                        fontSize = 12.sp
                    )
                }
                Button(
                    onClick = { showNightPassWarning = true },
                    enabled = canUseNightPass,
                    colors = ButtonDefaults.buttonColors(
                        containerColor = Color(0xFF39CCCC), 
                        disabledContainerColor = Color.DarkGray
                    )
                ) {
                    Text("SCHEDULE", color = Color.Black)
                }
            }
        }
    }

    if (showNightPassWarning) {
        AlertDialog(
            onDismissRequest = { showNightPassWarning = false },
            title = { Text("Heavy Warning", color = Color.Red, fontWeight = FontWeight.Bold) },
            text = { 
                Text("Activating a Night Pass will completely disable the Sleep Protocol (23:00-05:00) for tonight. \n\nThis increases the risk of sleep deprivation and digital addiction. You only get 3 of these per week to prevent forming a habit. Do you accept the risk?") 
            },
            confirmButton = {
                Button(
                    onClick = {
                        TimeManager.isNightPassScheduled = true
                        TimeManager.nightPassUsedThisWeek++
                        TimeManager.save(applicationContext)
                        showNightPassWarning = false
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = Color.Red)
                ) { Text("I UNDERSTAND") }
            },
            dismissButton = { TextButton(onClick = { showNightPassWarning = false }) { Text("CANCEL") } }
        )
    }
}

