 734 |             // 3. REWRITE IMPORTS (The Linker)
 735 |             function rewriteImports(code, currentPath) {
 736 |                 return code.replace(/(import|export)([\s\S]*?)(['"])([^'"]+)(['"])/g, (match, keyword, mid, q1, importPath, q2) => {
 737 |                     if(importPath.startsWith('.')) {
 738 |                         const resolved = resolvePath(currentPath, importPath);
 739 |                         
 740 |                         // FIX: Use effectiveRoot to strip the prefix (e.g. "DSE/ui.js" -> "ui.js")
 741 |                         const cleanKey = resolved.startsWith(effectiveRoot) ? resolved.substring(effectiveRoot.length) : resolved;
 742 |                         return `${keyword}${mid}${q1}${cleanKey}${q2}`;
 743 |                     }
 744 |                     return match;
 745 |                 });
 746 |             }
