 778 |             // Fix B: Rewrite External Scripts
 779 |             doc.querySelectorAll('script[src]').forEach(el => {
 780 |                 const src = el.getAttribute('src');
 781 |                 if(!src) return;
 782 |                 // Use effectiveRoot to find the actual file in cache
