 787 |                         // FIX: Use effectiveRoot to strip prefix for the inline import
 788 |                         const cleanKey = repoPath.startsWith(effectiveRoot) ? repoPath.substring(effectiveRoot.length) : repoPath;
 789 |                         const inlineScript = doc.createElement('script');
