/**
 * Scans the screen to see if "Eyecare" is mentioned.
 * This separates "Wifi Settings" (Safe) from "Eyecare App Info" (Danger).
 */
private fun isTargetingEyecare(root: AccessibilityNodeInfo): Boolean {
    // 1. Direct Name Check
    if (root.findAccessibilityNodeInfosByText("Eyecare").isNotEmpty()) return true
    if (root.findAccessibilityNodeInfosByText("com.eyecare.guard").isNotEmpty()) return true

    // 2. Window Title Check (some phones put app name in title bar)
    if (root.paneTitle?.toString()?.contains("Eyecare", ignoreCase = true) == true) return true

    return false
}

