// Checks if "Eyecare" is visible AND if it has a sibling/child saying "On"
private fun checkEyecareIsOn(root: AccessibilityNodeInfo): Boolean {
    val nodes = root.findAccessibilityNodeInfosByText("Eyecare")
    for (node in nodes) {
        // Samsung List Structure: Parent -> [Text: Eyecare, Text: On]
        val parent = node.parent ?: continue

        // Check siblings for "On"
        for (i in 0 until parent.childCount) {
            val child = parent.getChild(i) ?: continue
            val text = child.text?.toString() ?: ""
            val desc = child.contentDescription?.toString() ?: ""

            // Check for "On" (Active)
            if (text.equals("On", ignoreCase = true) || desc.equals("On", ignoreCase = true)) {
                return true
            }
        }
    }
    return false
}

private fun showShield() {
    try {
        if (shieldView != null) return // Already shown

        val view = android.view.View(this)
        view.setBackgroundColor(Color.TRANSPARENT)
        view.isClickable = true
        view.isFocusable = true 

        val params = WindowManager.LayoutParams(
            WindowManager.LayoutParams.MATCH_PARENT,
            WindowManager.LayoutParams.MATCH_PARENT,
            WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
            // FLAG_NOT_FOCUSABLE = Allows Home/Back keys to work (Don't trap user totally)
            // But View absorbs touches because it's full screen and clickable
            WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or 
            WindowManager.LayoutParams.FLAG_NOT_TOUCH_MODAL,
            android.graphics.PixelFormat.TRANSLUCENT
        )

        windowManager?.addView(view, params)
        shieldView = view
        DebugLogger.log("SHIELD", "Deployed.")
    } catch (e: Exception) {
        DebugLogger.log("SHIELD", "Failed to deploy: ${e.message}")
    }
}

private fun hideShield() {
    try {
        if (shieldView != null) {
            windowManager?.removeView(shieldView)
            shieldView = null
            DebugLogger.log("SHIELD", "Retracted.")
        }
    } catch (e: Exception) {}
}

