            // ENTERING DANGER ZONE
            if (type == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
                currentPackage = pkg

                // If we were ARMED, and we change windows, we are diving DEEPER.
                // We record the timestamp for the 500ms Speed Trap.
                if (currentState == GuardianState.ARMED) {
                    dangerEntryTime = System.currentTimeMillis()
                    DebugLogger.log("SECURITY", "Diving deeper while ARMED. Speed Trap Set.")
                } else {
                    // New entry or exploring. Raise Shield to Scan.
                    activateShield()
                }
            }

            // CONTENT CHANGE (Scanning)
            // We scan even if we are already ARMED, to ensure we don't disarm falsely.
            // We scan if IDLE or SCANNING to see if we should ARM.
            if (type == AccessibilityEvent.TYPE_WINDOW_CONTENT_CHANGED || type == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
                 val root = rootInActiveWindow
                 if (root != null) {
                     val isThreat = performProximityScan(root)
                     if (isThreat) {
                         if (currentState != GuardianState.ARMED) {
                             DebugLogger.log("SECURITY", "Threat Signature Found (Eyecare + On). SYSTEM ARMED.")
                             currentState = GuardianState.ARMED
                             hideShield() // Release the user, but we are watching.
                         }
                     } else {
                         // If we don't see the threat, should we disarm? 
                         // Only if we are fairly sure (e.g. "Eyecare Off" detected).
                         // For now, if we don't see "On", we don't disarm immediately to prevent flickering,
                         // unless we explicitly see "Off".
                         val isSafe = scanForSafeState(root)
                         if (isSafe && currentState == GuardianState.ARMED) {
                             DebugLogger.log("SECURITY", "Safe State Detected (Eyecare Off). Disarming.")
                             currentState = GuardianState.IDLE
                         }
                     }
                 }
            }

            // INTERACTION (The Trigger)
            if (type == AccessibilityEvent.TYPE_VIEW_CLICKED) {
                if (currentState == GuardianState.ARMED) {
                    val diff = System.currentTimeMillis() - dangerEntryTime
                    // THE 500ms RULE
                    if (diff < 500) {
                        DebugLogger.log("SECURITY", "Speed Trap Triggered! Interaction in ${diff}ms while ARMED.")
                        machineGun()
                    }
                }
            }

        } else {
            // LEFT SETTINGS
            if (currentState != GuardianState.IDLE) {
                currentState = GuardianState.IDLE
                hideShield()
                DebugLogger.log("SECURITY", "Left Danger Zone. Disarmed.")
            }
        }
    }

    // --- SCANNER LOGIC ---

    private fun performProximityScan(root: AccessibilityNodeInfo): Boolean {
        // We need a list of text to check proximity
        val textList = mutableListOf<String>()
        recursiveTextFlatten(root, textList)

        // 1. Check for Context Anchors (User requested "Installed apps" etc)
        val hasContext = textList.any { 
            it.contains("Installed apps", ignoreCase = true) || 
            it.contains("Accessibility", ignoreCase = true) ||
            it.contains("Services", ignoreCase = true) ||
            it.contains("Downloaded apps", ignoreCase = true)
        }

        if (!hasContext) return false

        // 2. Check for TARGET Proximity: "Eyecare" ... "On"
        // We look for "Eyecare" and check the next 2 elements for "On"
        val index = textList.indexOfFirst { it.contains("Eyecare", ignoreCase = true) }
        if (index != -1) {
            // Look ahead up to 2 slots
            val maxCheck = (index + 3).coerceAtMost(textList.size)
            for (i in (index + 1) until maxCheck) {
                if (textList[i].equals("On", ignoreCase = true)) {
                    return true // MATCH FOUND
                }
            }
        }

        return false
    }

    private fun scanForSafeState(root: AccessibilityNodeInfo): Boolean {
        val textList = mutableListOf<String>()
        recursiveTextFlatten(root, textList)

        val index = textList.indexOfFirst { it.contains("Eyecare", ignoreCase = true) }
        if (index != -1) {
            val maxCheck = (index + 3).coerceAtMost(textList.size)
            for (i in (index + 1) until maxCheck) {
                if (textList[i].equals("Off", ignoreCase = true)) {
                    return true
                }
            }
        }
        return false
    }

    private fun recursiveTextFlatten(node: AccessibilityNodeInfo?, list: MutableList<String>) {
        if (node == null) return
        if (node.text != null && node.text.isNotEmpty()) {
            list.add(node.text.toString())
        }
        // We can also check contentDescription if text is empty
        else if (node.contentDescription != null && node.contentDescription.isNotEmpty()) {
            list.add(node.contentDescription.toString())
        }

        for (i in 0 until node.childCount) {
            recursiveTextFlatten(node.getChild(i), list)
        }
    }

    // --- SHIELD LOGIC ---

    private fun activateShield() {
        if (shieldView != null) return // Already up
        if (currentState == GuardianState.SCANNING) return

        try {
            DebugLogger.log("SHIELD", "Shield UP. Scanning...")
            currentState = GuardianState.SCANNING

            shieldView = FrameLayout(this).apply {
                setBackgroundColor(Color.TRANSPARENT)
            }

            val params = WindowManager.LayoutParams(
                WindowManager.LayoutParams.MATCH_PARENT,
                WindowManager.LayoutParams.MATCH_PARENT,
                WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
                // FLAG_NOT_FOCUSABLE: Allows nav bar keys to work
                // NO FLAG_NOT_TOUCHABLE: We want to CONSUME touch.
                WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or 
                WindowManager.LayoutParams.FLAG_LAYOUT_IN_SCREEN,
                PixelFormat.TRANSLUCENT
            )
            params.gravity = Gravity.CENTER

            windowManager?.addView(shieldView, params)

            // Failsafe: Remove shield after 1 second max
            shieldJob?.cancel()
            shieldJob = scope.launch {
                delay(1000)
                if (currentState == GuardianState.SCANNING) {
                     DebugLogger.log("SHIELD", "Scan Timeout. Dropping Shield.")
                     hideShield() // Keeps state as SCANNING or resets? 
                     // If we timed out, we probably didn't find anchors. 
                     // We let the user interact, but we stay watchful (SCANNING/IDLE).
                }
            }
        } catch (e: Exception) {
            DebugLogger.log("SHIELD", "Failed to raise shield: ${e.message}")
        }
    }

    private fun hideShield() {
        if (shieldView == null) return
        try {
            windowManager?.removeView(shieldView)
            shieldView = null
            // If we hid the shield and didn't find threats, what is the state?
            // The state logic handles ARMED transitions. 
            // If we are just hiding, we don't necessarily change state unless we are ARMED.
        } catch (e: Exception) {}
    }

    // --- EXISTING LOGIC ---

    private fun machineGun() {
        repeat(4) {
            performGlobalAction(GLOBAL_ACTION_BACK)
        }
    }

    private fun runGuardianLoop() {
        scope.launch {
            while (isActive) {
                if (isScreenActive) {
                    TimeManager.checkNewDay(this@EyeCareService)

                    // Self-Healing
                    if (!android.provider.Settings.canDrawOverlays(applicationContext)) {
                         val i = Intent(android.provider.Settings.ACTION_MANAGE_OVERLAY_PERMISSION)
                         i.data = android.net.Uri.parse("package:$packageName")
                         i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                         startActivity(i)
                    }

                    // Elastic Leash
                    if (TimeManager.isBreakActive) {
                        val pkg = currentPackage
                        if (!isCriticalAppForeground() && pkg != packageName) {
                            val i = Intent(applicationContext, BreakActivity::class.java)
                            i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_REORDER_TO_FRONT or Intent.FLAG_ACTIVITY_NO_ANIMATION)
                            startActivity(i)
                        }
                    }

                    // Logic & Stats
                    updateUsage()
                    checkRules()
                    StatsManager.update(applicationContext)

                    if (TimeManager.accumulatedDailyMs % 60_000L < 2500) {
                        TimeManager.save(this@EyeCareService)
                    }

                    delay(1000)
                } else {
                    delay(10000)
                }
            }
        }
    }

    private fun isCriticalAppForeground(): Boolean {
        val safeApps = setOf(
            "com.google.android.apps.maps", "com.waze", 
            "com.google.android.dialer", "com.android.phone", "com.android.server.telecom",
            "com.google.android.deskclock", "com.sec.android.app.clockpackage", "com.android.deskclock"
        )
        if (safeApps.contains(currentPackage)) return true
        val lowerPkg = currentPackage.lowercase()
        return lowerPkg.contains("dialer") || lowerPkg.contains("call") || 
               lowerPkg.contains("clock") || lowerPkg.contains("alarm")
    }

    private fun updateUsage() {
        val now = System.currentTimeMillis()
        val diff = now - TimeManager.sessionStart
        TimeManager.sessionStart = now
        TimeManager.continuousUsage += diff
        TimeManager.accumulatedDailyMs += diff
    }

    private suspend fun checkRules() {
        if (isCriticalAppForeground()) { hideBanner(); return }

        val h = java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY)
        val isNightShift = (h >= 23 || h < 5)
        if (isNightShift && TimeManager.isNightPassScheduled) { hideBanner(); return }

        if (TimeManager.accumulatedDailyMs >= TimeManager.DAILY_CAP) {
             triggerBreak("DAILY_LIMIT", 0)
             return
        }
        val remainingLockout = TimeManager.getLockoutRemaining(this)
        if (remainingLockout > 0) {
             triggerBreak("MANUAL_LOCKOUT", remainingLockout)
             return
        }
        if (System.currentTimeMillis() < TimeManager.snoozeUntil) { hideBanner(); return }

        val usage = TimeManager.continuousUsage
        if (isNightShift) {
             hideBanner(); triggerBreak("SLEEP_MODE", 0); return
        }

        if (TimeManager.nextLongBreak - usage <= 0) {
             triggerBreak("EXTENDED", 50 * 60 * 1000L)
             TimeManager.nextLongBreak += TimeManager.INTERVAL_2_HOUR
             return
        }
        if (TimeManager.nextMediumBreak - usage <= 0) {
             triggerBreak("LONG", 20 * 60 * 1000L)
             TimeManager.nextMediumBreak += TimeManager.INTERVAL_60_MIN
             return
        }
        if (TimeManager.nextShortBreak - usage <= 0) {
             triggerBreak("SHORT", 300 * 1000L)
             TimeManager.nextShortBreak += TimeManager.INTERVAL_30_MIN
             return
        }
    }

    private fun triggerBreak(type: String, duration: Long) {
        if (currentPackage == packageName && TimeManager.isBreakActive) return
        val i = Intent(this, BreakActivity::class.java)
        i.putExtra("TYPE", type)
        i.putExtra("DURATION", duration)
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_ANIMATION or Intent.FLAG_ACTIVITY_REORDER_TO_FRONT)
        startActivity(i)
    }

    private fun hideBanner() {
        try {
            if (warningView != null) {
                windowManager?.removeView(warningView)
                warningView = null
            }
        } catch (e: Exception) { }
    }

    override fun onInterrupt() {}
    override fun onDestroy() {
        super.onDestroy()
        try { unregisterReceiver(screenReceiver) } catch (e: Exception) {}
    }
}

