package com.eyecare.guard

import android.accessibilityservice.AccessibilityService
import android.content.BroadcastReceiver
import android.content.Intent
import android.content.IntentFilter
import android.graphics.Color
import android.graphics.PixelFormat
import android.view.Gravity
import android.view.View
import android.view.WindowManager
import android.view.accessibility.AccessibilityEvent
import android.view.accessibility.AccessibilityNodeInfo
import android.widget.FrameLayout
import android.widget.TextView
import kotlinx.coroutines.*

class EyeCareService : AccessibilityService() {

    // CORE STATE
    private var isScreenActive = true
    private val job = SupervisorJob()
    private val scope = CoroutineScope(Dispatchers.Main + job)
    private var timerJob: Job? = null
    private var warningView: TextView? = null
    private var windowManager: WindowManager? = null
    private var currentPackage: String = ""

    // TACTICAL SHIELD STATE
    private var shieldView: FrameLayout? = null
    private var guardianState = GuardianState.IDLE
    private var shieldJob: Job? = null
    private var lastWindowChangeTime: Long = 0L

    // LEGACY SECURITY STATE
    private var verifiedSafeAppInfoSession = false
    private var wasInDangerZone = false

    enum class GuardianState {
        IDLE,       // Normal operation
        SCANNING,   // Shield UP, analyzing screen
        ARMED,      // Target acquired (Eyecare + On detected)
        FIRING      // Active countermeasures
    }

    // SCREEN RECEIVER
    private val screenReceiver = object : BroadcastReceiver() {
        override fun onReceive(context: android.content.Context, intent: Intent) {
            if (intent.action == Intent.ACTION_SCREEN_OFF) {
                isScreenActive = false
                TimeManager.lastScreenOffTs = System.currentTimeMillis()
                TimeManager.save(context)
                hideShield() // Safety drop
            } else if (intent.action == Intent.ACTION_SCREEN_ON) {
                isScreenActive = true
                val now = System.currentTimeMillis()
                if (TimeManager.lastScreenOffTs > 0 && (now - TimeManager.lastScreenOffTs) > 15 * 60 * 1000L) {
                    TimeManager.resetContinuous(context)
                    DebugLogger.log("TIMER", "Strict rest period completed. Usage reset.")
                }
                TimeManager.sessionStart = now
            }
        }
    }

    override fun onServiceConnected() {
        super.onServiceConnected() // Important
        startForegroundService()
        StatsManager.init(this)
        TimeManager.init(this)
        windowManager = getSystemService(WindowManager::class.java)
        TimeManager.sessionStart = System.currentTimeMillis()

        val filter = IntentFilter().apply {
            addAction(Intent.ACTION_SCREEN_ON)
            addAction(Intent.ACTION_SCREEN_OFF)
        }
        registerReceiver(screenReceiver, filter)

        runGuardianLoop()
        DebugLogger.log("INIT", "Guardian Service Started. Monitoring...")
    }

    private fun startForegroundService() {
        val channelId = "eyecare_min_channel"
        val nm = getSystemService(android.app.NotificationManager::class.java)
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
            val chan = android.app.NotificationChannel(
                channelId,
                "Monitor",
                android.app.NotificationManager.IMPORTANCE_MIN
            )
            chan.setShowBadge(false)
            nm.createNotificationChannel(chan)
        }
        val notif = androidx.core.app.NotificationCompat.Builder(this, channelId)
            .setContentTitle("Eyecare")
            .setContentText("Active")
            .setSmallIcon(android.R.drawable.ic_menu_view)
            .setPriority(androidx.core.app.NotificationCompat.PRIORITY_MIN)
            .setCategory(androidx.core.app.NotificationCompat.CATEGORY_SERVICE)
            .setOngoing(true)
            .build()
        startForeground(2024, notif)
    }

    override fun onAccessibilityEvent(event: AccessibilityEvent?) {
        if (event == null) return
        val pkg = event.packageName?.toString() ?: ""
        val className = event.className?.toString() ?: ""
        val type = event.eventType

        if (pkg == packageName) return
        if (NukeManager.isProtectionDisabled(this)) return

        // 1. GLOBAL STATE TRACKING
        if (type == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
            currentPackage = pkg
            lastWindowChangeTime = System.currentTimeMillis()

            // RESET State on Window Change (Unless ARMED, which persists one hop)
            if (guardianState == GuardianState.FIRING) {
                // Keep firing
            } else if (guardianState == GuardianState.ARMED) {
                 // We stay ARMED for the transition to the toggle screen
                 DebugLogger.log("STATE", "Window Changed while ARMED. Watching for speed entry...")
            } else {
                // Default Reset
                guardianState = GuardianState.IDLE
            }

            // DANGER ZONE DETECTION
            if (pkg.contains("settings") || pkg.contains("accessibility") || pkg.contains("packageinstaller")) {

                // START TACTICAL SHIELD
                // We only shield if we are not already firing
                if (guardianState != GuardianState.FIRING) {
                    showShield() // FREEZE USER
                    guardianState = GuardianState.SCANNING
                    DebugLogger.log("SHIELD", "Shield UP. Scanning for Anchors in $pkg...")
                }

                wasInDangerZone = true
            } else {
                wasInDangerZone = false
                hideShield() // Safe zone, drop shield
            }

            verifiedSafeAppInfoSession = false
        }

        val root = rootInActiveWindow ?: return

        // 2. SCANNING & ARMING LOGIC (While Shield is UP)
        if (guardianState == GuardianState.SCANNING) {
            val textList = mutableListOf<String>()
            collectText(root, textList)

            // ANCHOR LOGIC: Find "Eyecare" followed closely by "On"
            // Also look for "Installed apps" or "Downloaded apps" context if possible, but prioritize Eyecare+On

            val eyecareIndex = textList.indexOfFirst { it.contains("Eyecare", ignoreCase = true) }

            if (eyecareIndex != -1) {
                DebugLogger.log("SCAN", "Found Anchor 'Eyecare' at index $eyecareIndex")

                // Check proximity (next 2 nodes)
                var foundOn = false
                val maxSearch = (eyecareIndex + 3).coerceAtMost(textList.size)
                for (i in (eyecareIndex + 1) until maxSearch) {
                    if (textList[i].equals("On", ignoreCase = true) || textList[i].contains("On", ignoreCase = true)) {
                        foundOn = true
                        break
                    }
                }

                if (foundOn) {
                    guardianState = GuardianState.ARMED
                    DebugLogger.log("STATE", "*** TARGET ACQUIRED *** -> ARMED. 'Eyecare' + 'On' detected.")
                    hideShield() // Drop shield to allow user to proceed (into our trap)
                } else {
                    // Found Eyecare, but it says "Off" or nothing. Safe.
                    DebugLogger.log("SCAN", "Found 'Eyecare' but no 'On'. Safe/Inactive.")
                    hideShield()
                    guardianState = GuardianState.IDLE
                }
            } else {
                // No Eyecare text found yet. Keep shield up until timeout or next event.
            }
        }

        // 3. FIRING LOGIC (Speed Trap)
        // Logic: If ARMED, and we detect a touch, check time since window load.
        if (guardianState == GuardianState.ARMED) {

            if (type == AccessibilityEvent.TYPE_VIEW_CLICKED) {
                val timeSinceLoad = System.currentTimeMillis() - lastWindowChangeTime
                DebugLogger.log("TRAP", "Click detected. Time delta: \${timeSinceLoad}ms")

                // 500ms Speed Limit for ARMED targets
                if (timeSinceLoad < 500) {
                    DebugLogger.log("SECURITY", "*** SPEED TRAP TRIGGERED *** (Delta: $timeSinceLoad < 500ms)")
                    machineGun()
                    return
                } else {
                    // User waited long enough. 
                    // But wait! If they are clicking the Toggle now, we need to fallback to the Trinity Check.
                    // We don't disarm just yet, we let the Trinity check below handle the final toggle click.
                }
            }
        }

        // 4. LEGACY LAYERS (The Safety Nets)

        // A. THE TRINITY CHECK (Specific Toggle Screen Protection)
        // This catches them if they pass the Speed Trap but try to toggle OFF.
        if (pkg.contains("settings")) {
            val hasName = root.findAccessibilityNodeInfosByText("Eyecare").isNotEmpty()
            if (hasName) {
                val descriptionText = getString(R.string.accessibility_desc)
                val hasDescription = root.findAccessibilityNodeInfosByText(descriptionText).isNotEmpty()

                if (hasDescription) {
                    val switchNode = findSwitch(root)
                    val isChecked = switchNode?.isChecked == true

                    if (isChecked) {
                        // Trinity Complete: Name + Desc + ON -> User is trying to Turn OFF.
                        DebugLogger.log("SECURITY", "Trinity Violation: Attempt to disable service.")
                        machineGun()
                        return
                    }
                }
            }
        }

        // B. APP INFO FREEZE (Uninstall Protection)
        val hasUninstall = root.findAccessibilityNodeInfosByText("Uninstall").isNotEmpty()
        val hasForceStop = root.findAccessibilityNodeInfosByText("Force stop").isNotEmpty() || 
                           root.findAccessibilityNodeInfosByText("FORCE STOP").isNotEmpty()

        if (hasUninstall && hasForceStop) {
            val hasAppName = root.findAccessibilityNodeInfosByText("Eyecare").isNotEmpty()
            if (hasAppName) {
                 DebugLogger.log("SECURITY", "App Info Detected for Eyecare. KILLING.")
                 machineGun()
                 startTripwire()
                 return
            }

            // Generic App Info Logic (Freeze)
            if (!verifiedSafeAppInfoSession) {
                val isSafe = root.findAccessibilityNodeInfosByText("Permissions").isNotEmpty() || 
                             root.findAccessibilityNodeInfosByText("Notifications").isNotEmpty()
                if (isSafe) {
                    verifiedSafeAppInfoSession = true
                } else {
                    if (type == AccessibilityEvent.TYPE_VIEW_CLICKED) {
                        DebugLogger.log("SECURITY", "Freeze Violation: Interaction on unverified page.")
                        machineGun()
                    }
                }
            }
        }

        // C. DIALOG TRAP
        if (className.contains("Dialog") || className.contains("popup", ignoreCase = true)) {
             val sb = StringBuilder()
             collectTextRecursive(root, sb)
             val text = sb.toString()
             if (text.contains("Eyecare", ignoreCase = true) && 
                (text.contains("Stop", ignoreCase = true) || text.contains("Turn off", ignoreCase = true))) {
                 DebugLogger.log("SECURITY", "Dialog Trap: Destructive text detected.")
                 machineGun()
             }
        }
    }

    // --- TACTICAL SHIELD IMPLEMENTATION ---

    private fun showShield() {
        if (shieldView != null) return // Already UP
        if (!android.provider.Settings.canDrawOverlays(this)) return

        try {
            val params = WindowManager.LayoutParams(
                WindowManager.LayoutParams.MATCH_PARENT,
                WindowManager.LayoutParams.MATCH_PARENT,
                WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
                // FLAG_NOT_FOCUSABLE = Allow key events to pass behind (like Back btn), 
                // BUT we do NOT set FLAG_NOT_TOUCH_MODAL. This means we CONSUME touches.
                WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or 
                WindowManager.LayoutParams.FLAG_LAYOUT_IN_SCREEN,
                PixelFormat.TRANSLUCENT
            )
            params.gravity = Gravity.CENTER

            shieldView = FrameLayout(this).apply {
                setBackgroundColor(Color.TRANSPARENT) // Invisible
                // Optional: setBackgroundColor(Color.parseColor("#22FF0000")) // Debug Red Tint
            }

            windowManager?.addView(shieldView, params)
            // DebugLogger.log("SHIELD", "Visual Shield Deployed")

            // AUTO-DISMISS TIMER (1s MAX)
            shieldJob?.cancel()
            shieldJob = scope.launch {
                delay(1000)
                if (guardianState == GuardianState.SCANNING) {
                    DebugLogger.log("SHIELD", "Timeout: No anchors found. Dropping shield.")
                    hideShield()
                    guardianState = GuardianState.IDLE
                }
            }

        } catch (e: Exception) {
            DebugLogger.log("ERROR", "Failed to deploy shield: \${e.message}")
        }
    }

    private fun hideShield() {
        if (shieldView == null) return
        try {
            windowManager?.removeView(shieldView)
            shieldView = null
            // DebugLogger.log("SHIELD", "Shield Retracted")
        } catch (e: Exception) {
            shieldView = null
        }
    }

    // --- UTILS ---

    private fun collectText(node: AccessibilityNodeInfo?, list: MutableList<String>) {
        if (node == null) return
        if (node.text != null && node.text.isNotEmpty()) list.add(node.text.toString())
        if (node.contentDescription != null && node.contentDescription.isNotEmpty()) list.add(node.contentDescription.toString())
        for (i in 0 until node.childCount) {
            collectText(node.getChild(i), list)
        }
    }

    private fun collectTextRecursive(node: AccessibilityNodeInfo?, sb: StringBuilder) {
        if (node == null) return
        if (node.text != null) sb.append(node.text).append(" ")
        for (i in 0 until node.childCount) {
            collectTextRecursive(node.getChild(i), sb)
        }
    }

    private fun findSwitch(node: AccessibilityNodeInfo?): AccessibilityNodeInfo? {
        if (node == null) return null
        if (node.className == "android.widget.Switch") return node
        for (i in 0 until node.childCount) {
            val result = findSwitch(node.getChild(i))
            if (result != null) return result
        }
        return null
    }

    private fun machineGun() {
        guardianState = GuardianState.FIRING
        hideShield() // Drop shield so back button works
        DebugLogger.log("COMBAT", "!!! MACHINE GUN FIRED !!!")
        repeat(4) {
            performGlobalAction(GLOBAL_ACTION_BACK)
        }
        // Reset state after firing sequence
        scope.launch {
             delay(1000)
             guardianState = GuardianState.IDLE
        }
    }

    private fun startTripwire() {
        val i = Intent(applicationContext, LockdownActivity::class.java)
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        i.addFlags(Intent.FLAG_ACTIVITY_NO_ANIMATION)
        i.putExtra("BLOCK_TYPE", "SECURITY_TRIPWIRE")
        startActivity(i)
    }

    private fun runGuardianLoop() {
        timerJob = scope.launch {
            while (isActive) {
                if (isScreenActive) {
                    TimeManager.checkNewDay(this@EyeCareService)

                    if (!android.provider.Settings.canDrawOverlays(applicationContext)) {
                         val i = Intent(android.provider.Settings.ACTION_MANAGE_OVERLAY_PERMISSION)
                         i.data = android.net.Uri.parse("package:$packageName")
                         i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                         startActivity(i)
                    }

                    if (TimeManager.isBreakActive) {
                        val pkg = currentPackage
                        val isSafe = isCriticalAppForeground()
                        if (!isSafe && pkg != packageName) {
                            DebugLogger.log("LEASH", "Escaped to $pkg. Yanks back.")
                            val i = Intent(applicationContext, BreakActivity::class.java)
                            i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                            i.addFlags(Intent.FLAG_ACTIVITY_REORDER_TO_FRONT)
                            i.addFlags(Intent.FLAG_ACTIVITY_NO_ANIMATION)
                            startActivity(i)
                        }
                    }

                    updateUsage()
                    checkRules()
                    StatsManager.update(applicationContext)

                    if (TimeManager.accumulatedDailyMs % 60_000L < 2500) {
                        TimeManager.save(this@EyeCareService)
                    }
                    delay(1000)
                } else {
                    delay(10000)
                }
            }
        }
    }

    private fun isCriticalAppForeground(): Boolean {
        val safeApps = setOf(
            "com.google.android.apps.maps", "com.waze", 
            "com.google.android.dialer", "com.android.phone", "com.android.server.telecom",
            "com.google.android.deskclock", "com.sec.android.app.clockpackage", "com.android.deskclock"
        )
        val lowerPkg = currentPackage.lowercase()
        if (safeApps.contains(currentPackage)) return true
        return lowerPkg.contains("dialer") || lowerPkg.contains("call") || 
               lowerPkg.contains("clock") || lowerPkg.contains("alarm")
    }

    private fun updateUsage() {
        val now = System.currentTimeMillis()
        val diff = now - TimeManager.sessionStart
        TimeManager.sessionStart = now
        TimeManager.continuousUsage += diff
        TimeManager.accumulatedDailyMs += diff
    }

    private suspend fun checkRules() {
        if (isCriticalAppForeground()) {
             hideBanner()
             return
        }

        val h = java.util.Calendar.getInstance().get(java.util.Calendar.HOUR_OF_DAY)
        val isNightShift = (h >= 23 || h < 5)
        if (isNightShift && TimeManager.isNightPassScheduled) {
             hideBanner()
             return 
        }

        if (TimeManager.accumulatedDailyMs >= TimeManager.DAILY_CAP) {
             triggerBreak("DAILY_LIMIT", 0)
             return
        }

        val remainingLockout = TimeManager.getLockoutRemaining(this)
        if (remainingLockout > 0) {
             triggerBreak("MANUAL_LOCKOUT", remainingLockout)
             return
        }

        if (System.currentTimeMillis() < TimeManager.snoozeUntil) {
             hideBanner()
             return
        }

        val usage = TimeManager.continuousUsage

        if (isNightShift) {
             hideBanner()
             triggerBreak("SLEEP_MODE", 0)
             return
        }

        if (TimeManager.nextLongBreak - usage <= 0) {
             triggerBreak("EXTENDED", 50 * 60 * 1000L)
             TimeManager.nextLongBreak += TimeManager.INTERVAL_2_HOUR
             return
        }
        if (TimeManager.nextMediumBreak - usage <= 0) {
             triggerBreak("LONG", 20 * 60 * 1000L)
             TimeManager.nextMediumBreak += TimeManager.INTERVAL_60_MIN
             return
        }
        if (TimeManager.nextShortBreak - usage <= 0) {
             triggerBreak("SHORT", 300 * 1000L)
             TimeManager.nextShortBreak += TimeManager.INTERVAL_30_MIN
             return
        }
    }

    private fun triggerBreak(type: String, duration: Long) {
        if (currentPackage == packageName && TimeManager.isBreakActive) return
        val i = Intent(this, BreakActivity::class.java)
        i.putExtra("TYPE", type)
        i.putExtra("DURATION", duration)
        i.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_ANIMATION or Intent.FLAG_ACTIVITY_REORDER_TO_FRONT)
        startActivity(i)
    }

    private fun hideBanner() {
        try {
            if (warningView != null) {
                val container = warningView?.tag as? View
                if (container != null && container.parent != null) {
                    windowManager?.removeView(container)
                }
                warningView = null
            }
        } catch (e: Exception) { }
    }

    override fun onInterrupt() {
        hideShield()
    }

    override fun onDestroy() {
        super.onDestroy()
        hideShield()
        try { unregisterReceiver(screenReceiver) } catch (e: Exception) {}
    }
}
